function DashboardPanel({id,wide=false,children,onHide,onMoveLeft,onMoveRight,onDragStart,onDrop,onDragOver}:{id:string;wide?:boolean;children:any;onHide:()=>void;onMoveLeft:()=>void;onMoveRight:()=>void;onDragStart:()=>void;onDrop:()=>void;onDragOver:(e:any)=>void}){return <div draggable onDragStart={onDragStart} onDrop={onDrop} onDragOver={onDragOver} className={(wide?'dashboard-panel-wide md:col-span-5 md:row-span-1 ':'premium-card dashboard-panel-small p-4 md:col-span-1 md:row-span-1 ')+'group relative cursor-move'}><div className="absolute right-2 top-2 z-10 hidden gap-1 group-hover:flex"><button type="button" className="rounded-md border border-slate-200 bg-white/90 px-1.5 py-0.5 text-[10px] text-slate-600 shadow-sm" title="Move left" onClick={e=>{e.stopPropagation();onMoveLeft()}}>←</button><button type="button" className="rounded-md border border-slate-200 bg-white/90 px-1.5 py-0.5 text-[10px] text-slate-600 shadow-sm" title="Move right" onClick={e=>{e.stopPropagation();onMoveRight()}}>→</button><button type="button" className="rounded-md border border-slate-200 bg-white/90 px-1.5 py-0.5 text-[10px] text-slate-600 shadow-sm" title="Hide panel" onClick={e=>{e.stopPropagation();onHide()}}>Hide</button></div>{children}</div>}
function normSkillName(s:string){return (s||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim()}
const REAL_SKILL_KEYWORDS=['python','django','fastapi','flask','java','javascript','typescript','react','vue','angular','node','sql','postgres','postgresql','mysql','redis','docker','kubernetes','k8s','aws','azure','gcp','linux','git','ci cd','terraform','ansible','rest','api','graphql','microservices','celery','rabbitmq','kafka','spark','elasticsearch','opensearch','llm','rag','langchain','langgraph','embedding','embeddings','vector','semantic search','machine learning','ml','nlp','pytorch','tensorflow','pandas','numpy','scikit','openai'];
const NON_SKILL_WORDS=['strategy','strategic','stakeholder','communication','collaboration','leadership','ownership','management','consulting','business','work','working','experience','years','team','teams','agile','scrum','problem solving','analytical','mindset','passion','motivation','degree','bachelor','master','english','german','deutsch','remote','hybrid'];
function isRealSkill(s:string){const n=normSkillName(s); if(!n||n.length<2)return false; if(n.length>80)return false; const generic=['experience','years','team','teams','work','working','degree','bachelor','master']; if(generic.includes(n))return false; return true}
function SkillLabels({ev,overrides={},onToggle,limit=8}:{ev:any;overrides?:Record<string,string>;onToggle?:(s:string,currentTone?:string)=>void;limit?:number}){if(!ev)return <span className="text-slate-400">—</span>; const all=[...(ev.required_skills||[]),...(ev.missing_skills||[]),...(ev.matched_skills||[])].filter((v:string,i:number,a:string[])=>v&&a.indexOf(v)===i); const missing=new Set((ev.missing_skills||[]).map(normSkillName)); const meta=(s:string)=>ev.skill_statuses?.[s]; const status=(s:string)=>typeof meta(s)==='string'?meta(s):meta(s)?.status; const label=(s:string)=>typeof meta(s)==='object'&&meta(s)?.display?meta(s).display:s; const tone=(s:string)=>overrides[normSkillName(s)] || (status(s)==='match'?'green':status(s)==='weak'?'yellow':missing.has(normSkillName(s))?'red':'red'); const skills=all.filter(isRealSkill).sort((a:string,b:string)=>{const score=(x:string)=>(tone(x)==='green'?3:tone(x)==='yellow'?2:1)+(overrides[normSkillName(x)]?2:0);return score(b)-score(a)}).slice(0,limit); if(!skills.length)return <span className="text-slate-400">—</span>; return <div className="flex flex-wrap gap-1" title={all.filter(isRealSkill).map(label).join(', ')}>{skills.map((x:string,i:number)=><button type="button" key={i} title="Click to cycle: red → yellow → green. Applies to this skill name everywhere." onClick={e=>{e.stopPropagation();onToggle&&onToggle(x,tone(x))}} className="bg-transparent p-0"><Badge tone={tone(x)}>{label(x)}</Badge></button>)}</div>}
function MatchGapPopup({ev}:{ev:any}){const matches=ev?.main_match_reasons||[];const gaps=ev?.main_gaps||[];const summary=ev?.summary;const ref=useRef<HTMLDivElement|null>(null);const closeTimer=useRef<number|null>(null);const[open,setOpen]=useState(false);const[pos,setPos]=useState<any>({left:0,top:0,width:448});function cancelClose(){if(closeTimer.current){window.clearTimeout(closeTimer.current);closeTimer.current=null}}function scheduleClose(){cancelClose();closeTimer.current=window.setTimeout(()=>setOpen(false),120)}function show(){cancelClose();const r=ref.current?.getBoundingClientRect();if(!r)return;const width=Math.min(448,window.innerWidth*.8);const height=288;const left=Math.max(8,Math.min(r.left,window.innerWidth-width-8));const below=r.bottom+6;const top=below+height>window.innerHeight?Math.max(8,r.top-height-6):below;setPos({left,top,width});setOpen(true)}const panel=<div onMouseEnter={cancelClose} onMouseLeave={scheduleClose} onClick={e=>e.stopPropagation()} style={pos} className="fixed z-[9999] max-h-72 max-w-[80vw] overflow-auto rounded-xl border border-slate-200 bg-white p-2.5 text-[10px] leading-snug text-slate-700 shadow-2xl dark:border-white/10 dark:bg-slate-950 dark:text-slate-200"><div className="mb-1.5 text-[11px] font-semibold text-slate-900 dark:text-slate-50">Concise analysis</div>{summary&&<p className="mb-2 text-slate-600 dark:text-slate-300">{summary}</p>}<div className="grid gap-2"><div><b className="text-green-700 dark:text-green-300">Matches</b><ul className="mt-1 list-disc space-y-0.5 pl-4">{(matches.length?matches:['—']).map((x:any,i:number)=><li key={i}>{x}</li>)}</ul></div><div><b className="text-red-700 dark:text-red-300">Gaps</b><ul className="mt-1 list-disc space-y-0.5 pl-4">{(gaps.length?gaps:['—']).map((x:any,i:number)=><li key={i}>{x}</li>)}</ul></div></div></div>;return <div ref={ref} onMouseEnter={show} onMouseLeave={scheduleClose} className="relative break-words leading-snug"><b>Match:</b> {matches[0]||'—'}<br/><b>Gap:</b> {gaps[0]||'—'}{open&&createPortal(panel,document.body)}</div>}
function messageText(value:any){return typeof value==='string'?value:value?.detail||value?.message||JSON.stringify(value,null,2)}
function StatusMessage({tone='success',children,title,compact=false}:{tone?:'success'|'error'|'info';children:any;title?:string;compact?:boolean}){if(!children)return null;const icon=tone==='error'?'!':tone==='success'?'✓':'i';return <div className={(compact?'status-message-compact ':'')+'status-message status-message-'+tone} role={tone==='error'?'alert':'status'}><span className="status-message-icon" aria-hidden="true">{icon}</span><div className="min-w-0">{title&&<div className="status-message-title">{title}</div>}<div className="status-message-body">{children}</div></div></div>}
function ErrorBox({error}:{error:any}){return error?<div className="field-error-message" role="alert"><span className="field-error-icon" aria-hidden="true">!</span><span>{messageText(error)}</span></div>:null}
function SuccessMessage({message,children,title,compact=false}:{message?:any;children?:any;title?:string;compact?:boolean}){const body=children??message;return body?<StatusMessage tone="success" title={title} compact={compact}>{body}</StatusMessage>:null}
function EyeIcon({off=false}:{off?:boolean}){return <svg className="password-toggle-icon" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M2.25 12s3.5-6.25 9.75-6.25S21.75 12 21.75 12 18.25 18.25 12 18.25 2.25 12 2.25 12Z"/><path d="M12 14.75a2.75 2.75 0 1 0 0-5.5 2.75 2.75 0 0 0 0 5.5Z"/>{off&&<path d="M4.75 4.75 19.25 19.25"/>}</svg>}
function PasswordInput({value,onChange,placeholder,autoComplete,invalid=false}:{value:string;onChange:(e:any)=>void;placeholder:string;autoComplete?:string;invalid?:boolean}){const[visible,setVisible]=useState(false);return <span className="password-field"><input type={visible?'text':'password'} autoComplete={autoComplete} placeholder={placeholder} aria-invalid={invalid||undefined} value={value} onChange={onChange}/><button type="button" className="password-toggle" aria-label={visible?'Hide password':'Show password'} title={visible?'Hide password':'Show password'} onClick={()=>setVisible(!visible)}><EyeIcon off={!visible}/></button></span>}
function Loading({show}:{show:boolean}){return show?<p className="p-4 text-slate-500">Loading…</p>:null}
function Empty({children}:{children:any}){return <div className="rounded bg-white p-8 text-center text-slate-500 shadow-sm">{children}</div>}
function DashboardEmptyState({onUseDemoData,demoLoading,isFriendSubmitter=false}:{onUseDemoData:()=>void;demoLoading:boolean;isFriendSubmitter?:boolean}){const addPath=isFriendSubmitter?'/public-submit':'/add';const actions=[{title:'Add your first job',body:'Save one role manually. A URL is enough; details can be enriched later.',to:addPath,icon:'＋',primary:true},{title:'Import from links',body:'Paste multiple job URLs and turn scattered leads into dashboard rows.',to:addPath,icon:'⇩'},{title:'Paste CV/profile',body:'Add your profile so generated prompts score roles against your real goals.',to:'/settings/profile',icon:'CV'}];return <section className="premium-card overflow-hidden p-6 text-left shadow-xl"><div className="grid gap-6 lg:grid-cols-[1fr_.9fr] lg:items-center"><div><p className="mb-2 text-xs font-semibold uppercase tracking-[0.25em] text-blue-600">Start here</p><h2 className="text-2xl font-bold tracking-tight text-slate-950 md:text-3xl dark:text-white">Add your first job</h2><p className="mt-3 max-w-2xl text-sm leading-6 text-slate-600 dark:text-slate-300">Your dashboard is empty. Add a job link, import a batch of links, try demo data, or paste your CV/profile first. Next, DACHApply will organize roles, help generate ChatGPT analysis, import structured JSON, and show fit scores, priorities, gaps, statuses, and follow-up reminders.</p><div className="mt-5 flex flex-wrap gap-2"><Link className="btn-primary" to={addPath}>Add your first job</Link><button type="button" className="btn" onClick={onUseDemoData} disabled={demoLoading}>{demoLoading?'Adding demo data…':'Use demo data'}</button><Link className="btn-muted" to="/settings/profile">Paste CV/profile</Link></div></div><div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-1">{actions.map(a=><Link key={a.title} to={a.to} className={(a.primary?'border-blue-200 bg-blue-50 text-blue-950 dark:border-blue-400/20 dark:bg-blue-500/10 dark:text-blue-100':'border-slate-200 bg-white text-slate-700 dark:border-white/10 dark:bg-white/5 dark:text-slate-200')+' block rounded-2xl border p-4 text-left shadow-sm transition hover:-translate-y-0.5 hover:shadow-md'}><div className="mb-2 flex items-center gap-3"><span className="grid h-9 w-9 shrink-0 place-items-center rounded-full bg-white text-sm font-bold text-blue-700 shadow-sm dark:bg-slate-950 dark:text-blue-200">{a.icon}</span><b>{a.title}</b></div><p className="text-sm leading-5 text-slate-600 dark:text-slate-300">{a.body}</p></Link>)}<button type="button" onClick={onUseDemoData} disabled={demoLoading} className="block rounded-2xl border border-emerald-200 bg-emerald-50 p-4 text-left text-emerald-950 shadow-sm transition hover:-translate-y-0.5 hover:shadow-md disabled:opacity-60 dark:border-emerald-400/20 dark:bg-emerald-500/10 dark:text-emerald-100"><div className="mb-2 flex items-center gap-3"><span className="grid h-9 w-9 shrink-0 place-items-center rounded-full bg-white text-sm font-bold text-emerald-700 shadow-sm dark:bg-slate-950 dark:text-emerald-200">▶</span><b>Use demo data</b></div><p className="text-sm leading-5 text-emerald-900/80 dark:text-emerald-100/80">Create a few sample roles with fit scores so you can explore filters, status changes, and analysis immediately.</p></button></div></div><p className="mt-5 rounded-2xl bg-slate-50 p-3 text-sm text-slate-600 dark:bg-white/5 dark:text-slate-300"><b>What happens next:</b> select saved jobs, click Analyze selected jobs, paste the generated prompt into ChatGPT, then import the JSON response to populate recommendations and next actions.</p></section>}
function ImportResultSummary({result,compact=false}:{result:any;compact?:boolean}){const importedJobs=(result?.imported_jobs||result?.jobs||[]).filter((j:any)=>j.job_id);const jobsFound=result?.jobs_found??importedJobs.length;const evalCount=result?.count??result?.created_ids?.length??0;return <SuccessMessage title="Import successful" compact={compact}>{result.type==='jobs'?<><p>{jobsFound} job{jobsFound===1?'':'s'} found and imported.</p>{importedJobs.length>0&&<ol className="mt-3 list-decimal space-y-1 pl-5">{importedJobs.map((j:any)=><li key={j.job_id}><b>{j.company||'Unknown company'}</b> - {displayJobTitle(j.title)||'Untitled role'} position</li>)}</ol>}</>:<><p>Imported {evalCount} evaluation{evalCount===1?'':'s'}.</p>{result.created_ids&&<p className="mt-2">Evaluation IDs: {result.created_ids.join(', ')}</p>}</>}</SuccessMessage>}
