function storedPromptPrefs(){try{return JSON.parse(localStorage.getItem(promptPrefsKey)||'{}')}catch{localStorage.removeItem(promptPrefsKey);return {}}}
function promptJobSectionIndex(prompt:string){const markers=['\nJOBS:','\nJOBS NEEDING DETAILS:','\nJOB LINKS:'];const hits=markers.map(m=>prompt.indexOf(m)).filter(i=>i>=0);return hits.length?Math.min(...hits):-1}
function promptEditablePrefix(prompt:string){const i=promptJobSectionIndex(prompt);return (i>=0?prompt.slice(0,i):prompt).trimEnd()}
function applyPromptEditablePrefix(prompt:string,prefix?:string){if(!prefix?.trim())return prompt;const schemaMarker='\nEXPECTED JSON SCHEMA:';if(!prefix.includes(schemaMarker)&&prompt.includes(schemaMarker)){return prefix.trimEnd()+prompt.slice(prompt.indexOf(schemaMarker))}const i=promptJobSectionIndex(prompt);return i>=0?prefix.trimEnd()+prompt.slice(i):prefix.trimEnd()}
function Nav(){const nav=useNavigate();const loc=useLocation();const[dark,setDark]=useState(()=>localStorage.getItem('dachapply_theme')==='dark');const[user,setUser]=useState<any>(()=>storedUser());const[menu,setMenu]=useState(false);useEffect(()=>{document.documentElement.classList.toggle('dark',dark);localStorage.setItem('dachapply_theme',dark?'dark':'light')},[dark]);useEffect(()=>{setUser(storedUser());setMenu(false)},[loc.pathname]);async function toggleProfile(){setMenu(!menu)}async function logout(){await api('/auth/logout/',{method:'POST'}).catch(()=>{});localStorage.removeItem('dachapply_user');setUser(null);setMenu(false);nav('/login')}return <div className="app-nav sticky top-0 z-20 border-b px-2 py-1 backdrop-blur-xl"><div className="flex w-full items-center justify-between gap-2"><div className="flex min-w-0 items-center gap-2"><Link to={user?'/':'/login'} className="group flex shrink-0 items-center gap-1.5 text-slate-900"><span className="app-brand-mark grid h-6 w-6 place-items-center rounded-md text-[10px] font-bold text-white">D</span><b className="text-sm tracking-tight">DACHApply</b></Link>{user&&<div className="hidden min-w-0 items-center gap-0.5 text-xs sm:flex"><Link className="nav-link" to="/public-submit">Submit for friend</Link><Link data-tour="data-nav" className="nav-link" to="/export">Data</Link><Link data-tour="bookmarklet-nav" className="nav-link" to="/bookmarklet">Bookmarklet</Link><Link data-tour="profile-nav" className="nav-link" to="/settings/profile">Profile</Link></div>}</div><div className="ml-auto flex shrink-0 items-center justify-end gap-1.5">{!user&&<div className="hidden items-center gap-0.5 sm:flex"><Link className="nav-link" to="/login?mode=login">Login</Link><Link className="btn-primary" to="/login?mode=register">Start</Link></div>}<button className="btn h-7 px-1.5" title={dark?'Switch to light mode':'Switch to dark mode'} onClick={()=>setDark(!dark)}>{dark?'☀':'☾'}</button>{user&&<span className="relative"><button className="btn h-7 w-7 justify-center rounded-full px-0 text-[11px]" title={user.username} onClick={toggleProfile}>{String(user.username||'U').slice(0,1).toUpperCase()}</button>{menu&&<div className="absolute right-0 top-8 z-40 w-40 rounded-xl border bg-white p-2 text-slate-900 shadow-xl dark:border-white/10 dark:bg-slate-950 dark:text-slate-100"><div className="mb-2 truncate px-2 text-xs text-slate-500">Signed in as<br/><b className="text-slate-800 dark:text-slate-100">{user.username}</b></div><Link className="btn-muted mb-1 w-full justify-center" to="/settings/account" onClick={()=>setMenu(false)}>Account settings</Link><div className="my-1 border-t border-slate-200 dark:border-white/10"/><button className="btn-danger w-full justify-center" onClick={logout}>Logout</button></div>}</span>}</div></div></div>}

function RefreshSamePageLinks(){useEffect(()=>{function onClick(e:MouseEvent){if(e.defaultPrevented||e.metaKey||e.ctrlKey||e.shiftKey||e.altKey)return;const a=(e.target as HTMLElement)?.closest?.('a[href]') as HTMLAnchorElement|null;if(!a||a.target||a.hasAttribute('download'))return;let url:URL;try{url=new URL(a.href,window.location.href)}catch{return}if(url.origin!==window.location.origin)return;const clicked=url.pathname+url.search+url.hash;const current=window.location.pathname+window.location.search+window.location.hash;if(clicked===current){e.preventDefault();window.location.reload()}}document.addEventListener('click',onClick,true);return()=>document.removeEventListener('click',onClick,true)},[]);return null}
function RequireAuth({children}:{children:any}){const[ok,setOk]=useState<boolean|null>(null);useEffect(()=>{api('/auth/me/').then(u=>{localStorage.setItem('dachapply_user',JSON.stringify(u));window.dispatchEvent(new Event('dachapply_user_changed'));setOk(true)}).catch(()=>{localStorage.removeItem('dachapply_user');window.dispatchEvent(new Event('dachapply_user_changed'));setOk(false)})},[]);if(ok===null)return <Loading show/>;return ok?children:<Navigate to="/login" replace/>}
function Login(){const nav=useNavigate();const loc=useLocation();const formRef=useRef<HTMLFormElement|null>(null);const initialMode=new URLSearchParams(loc.search).get('mode')==='login'?'login':'register';const[form,set]=useState<any>({username:'',password:'',email:''});const[err,setErr]=useState('');const[msg,setMsg]=useState('');const[loading,setLoading]=useState(false);const[mode,setMode]=useState<'login'|'register'|'forgot'>(initialMode);useEffect(()=>{const next=new URLSearchParams(loc.search).get('mode');if(next==='login'||next==='register')setMode(next)},[loc.search]);function choose(next:'login'|'register'|'forgot'){setErr('');setMsg('');setMode(next);window.setTimeout(()=>formRef.current?.querySelector('input')?.focus(),50)}async function sub(e:any){e.preventDefault();setErr('');setMsg('');setLoading(true);try{if(mode==='forgot'){const r=await api('/auth/password-reset/',{method:'POST',body:{email:form.email}});setMsg(r.detail);return}const u=await api(mode==='login'?'/auth/login/':'/auth/register/',{method:'POST',body:form});localStorage.setItem('dachapply_user',JSON.stringify(u));if(mode==='register'){localStorage.setItem('dachapply_onboarding_pending','1');localStorage.setItem('dachapply_onboarding_step','0');localStorage.setItem('dachapply_onboarding_done','[]');localStorage.setItem('dachapply_onboarding_'+String(u.username||form.email||'user')+'_pending','1');window.dispatchEvent(new Event('dachapply_onboarding_start'))}nav('/',{replace:true,state:{onboarding:true}})}catch(x:any){setErr(x.detail||(mode==='login'?'Login failed':mode==='register'?'Register failed':'Reset request failed'))}finally{setLoading(false)}}async function tryDemo(){setErr('');setMsg('');setLoading(true);try{const u=await api('/auth/login/',{method:'POST',body:{username:'demo@dachapply.com',password:'DemoApply2026!'}});localStorage.setItem('dachapply_user',JSON.stringify(u));Object.keys(localStorage).filter(k=>k.startsWith('dachapply_onboarding')).forEach(k=>localStorage.removeItem(k));nav('/',{replace:true})}catch(x:any){setErr(x?.detail||'Demo account is not available in this environment.')}finally{setLoading(false)}}const formTitle=mode==='login'?'Welcome back':mode==='register'?'Start your private dashboard':'Reset password';const formCopy=mode==='login'?'Sign in to keep your search moving.':mode==='register'?'Create your account in seconds. Add one role, generate an analysis prompt, and feel organized today.':'Enter your account email to receive a reset link.';const benefit=['Know which jobs deserve your energy','Turn messy job links into structured decisions','Track applications, interviews, and follow-ups','Export your data whenever you want'];const trustSignals=['Your data stays in your private dashboard','No paid LLM API required','You control what gets pasted into ChatGPT','Export/delete anytime'];return <main className="overflow-hidden"><section className="mx-auto grid max-w-7xl gap-8 px-4 py-10 md:px-6 lg:grid-cols-[1.08fr_.92fr] lg:items-center lg:py-16"><div><div className="mb-5 inline-flex items-center gap-2 rounded-full border border-blue-200 bg-white/70 px-3 py-1 text-xs font-semibold text-blue-900 shadow-sm backdrop-blur dark:border-white/10 dark:bg-white/10 dark:text-blue-100"><span className="h-2 w-2 rounded-full bg-emerald-400 shadow-[0_0_16px_rgba(52,211,153,.9)]"/>Private job intelligence for DACH applications</div><h1 className="max-w-4xl text-5xl font-black tracking-tight text-slate-950 md:text-6xl dark:text-white">Stop collecting job links. Start applying to the roles you can actually win.</h1><p className="mt-5 max-w-2xl text-lg leading-8 text-slate-600 dark:text-slate-300">DACHApply turns scattered job posts into a calm command center: priority scores, fit analysis, missing skills, application dates, interview stages, and follow-up reminders in one private workspace.</p><div className="mt-7 flex flex-wrap gap-3"><button type="button" className="btn-primary px-5 py-3 text-sm" onClick={()=>choose('register')}>Create free account</button><button type="button" className="btn px-5 py-3 text-sm" onClick={tryDemo} disabled={loading}>Try demo</button><button type="button" className="btn px-5 py-3 text-sm" onClick={()=>choose('login')}>I already have an account</button></div><div className="mt-7 grid max-w-3xl gap-3 sm:grid-cols-2">{benefit.map(x=><div key={x} className="flex items-center gap-2 rounded-2xl border border-white/70 bg-white/65 p-3 text-sm font-medium text-slate-700 shadow-sm backdrop-blur dark:border-white/10 dark:bg-white/5 dark:text-slate-200"><span className="grid h-6 w-6 shrink-0 place-items-center rounded-full bg-emerald-100 text-emerald-700 dark:bg-emerald-400/15 dark:text-emerald-200">✓</span>{x}</div>)}</div><div className="mt-4 grid max-w-3xl gap-2 sm:grid-cols-2">{trustSignals.map(x=><div key={x} className="flex items-center gap-2 rounded-2xl border border-emerald-200/70 bg-emerald-50/80 p-3 text-sm font-semibold text-emerald-950 shadow-sm backdrop-blur dark:border-emerald-400/20 dark:bg-emerald-500/10 dark:text-emerald-100"><span className="grid h-6 w-6 shrink-0 place-items-center rounded-full bg-white text-emerald-700 shadow-sm dark:bg-slate-950 dark:text-emerald-200">🔒</span>{x}</div>)}</div></div><aside className="premium-card relative p-4 md:p-6"><div className="absolute -right-10 -top-10 h-32 w-32 rounded-full bg-blue-500/20 blur-3xl"/><div className="absolute -bottom-10 -left-10 h-32 w-32 rounded-full bg-purple-500/20 blur-3xl"/><div className="relative rounded-3xl border border-slate-200 bg-white p-4 shadow-2xl dark:border-white/10 dark:bg-slate-950/80"><div className="mb-4 flex items-center justify-between"><div><div className="text-xs uppercase tracking-[0.25em] text-slate-400">Today</div><div className="text-xl font-bold">Job command center</div></div><Badge tone="green">Ready</Badge></div><div className="grid grid-cols-3 gap-2 text-center"><div className="rounded-2xl bg-slate-50 p-3 dark:bg-white/5"><div className="text-2xl font-bold">82%</div><div className="text-[11px] text-slate-500">Fit score</div></div><div className="rounded-2xl bg-slate-50 p-3 dark:bg-white/5"><div className="text-2xl font-bold">5</div><div className="text-[11px] text-slate-500">To apply</div></div><div className="rounded-2xl bg-slate-50 p-3 dark:bg-white/5"><div className="text-2xl font-bold">2</div><div className="text-[11px] text-slate-500">Follow-ups</div></div></div><div className="mt-4 space-y-3"><div className="rounded-2xl border border-slate-100 p-3 dark:border-white/10"><div className="flex items-start justify-between gap-3"><div><b>Senior Python Developer</b><div className="text-sm text-slate-500">Vienna · hybrid</div></div><Badge tone="green">apply</Badge></div><div className="mt-3 flex flex-wrap gap-1"><Badge tone="green">Python</Badge><Badge tone="green">Django</Badge><Badge tone="yellow">German B1</Badge><Badge tone="blue">82%</Badge></div></div><div className="rounded-2xl border border-slate-100 p-3 dark:border-white/10"><div className="flex items-start justify-between gap-3"><div><b>Data Engineer</b><div className="text-sm text-slate-500">Berlin · remote</div></div><Badge tone="yellow">maybe</Badge></div><div className="mt-3 text-xs text-slate-600 dark:text-slate-300"><b>Match:</b> Python, SQL, cloud projects<br/><b>Gap:</b> Kafka ownership unclear</div></div></div></div><form ref={formRef} onSubmit={sub} className="relative mt-5 space-y-3 rounded-3xl border border-slate-200 bg-white/90 p-5 shadow-xl backdrop-blur dark:border-white/10 dark:bg-slate-950/85"><div className="mb-1"><h2 className="text-2xl font-bold">{formTitle}</h2><p className="mt-1 text-sm text-slate-500">{formCopy}</p></div>{mode==='login'&&<input autoComplete="email" placeholder="email address" value={form.username} onChange={e=>set({...form,username:e.target.value})}/>} {mode!=='login'&&<input type="email" autoComplete="email" placeholder="email address" aria-invalid={!!err&&mode==='forgot'} value={form.email} onChange={e=>set({...form,email:e.target.value,username:e.target.value})}/>} {mode!=='forgot'&&<PasswordInput autoComplete={mode==='register'?'new-password':'current-password'} placeholder="password" invalid={!!err} value={form.password} onChange={e=>set({...form,password:e.target.value})}/>} {mode==='register'&&<input placeholder="Friend username or email (optional)" value={form.submit_for_username||''} onChange={e=>set({...form,submit_for_username:e.target.value})}/>}<button className="btn-primary w-full justify-center py-3 text-sm" disabled={loading}>{loading?'Please wait…':mode==='login'?'Login':mode==='register'?'Create my dashboard':'Send reset email'}</button>{mode!=='forgot'&&<button type="button" className="btn w-full justify-center py-3 text-sm" disabled={loading} onClick={tryDemo}>Try demo dashboard</button>}{mode==='login'&&<button type="button" className="btn-muted w-full justify-center" onClick={()=>choose('forgot')}>Forgot password?</button>}{mode==='login'&&<button type="button" className="btn-muted w-full justify-center" onClick={()=>choose('register')}>Create new account</button>}{mode!=='login'&&<button type="button" className="btn-muted w-full justify-center" onClick={()=>choose('login')}>Back to login</button>}<SuccessMessage message={msg}/><ErrorBox error={err}/><p className="text-center text-xs text-slate-500">Private beta. By joining, you can manage your own job-search data and export it anytime.</p></form></aside></section><section className="mx-auto max-w-7xl px-4 pb-14 md:px-6"><div className="grid gap-4 md:grid-cols-3"><div className="premium-card p-5"><div className="mb-3 text-3xl">🔎</div><h3 className="text-lg font-bold">Capture without chaos</h3><p className="mt-2 text-sm leading-6 text-slate-600 dark:text-slate-300">Add links manually or with the bookmarklet. DACHApply keeps company, role, location, URL, description, and source together.</p></div><div className="premium-card p-5"><div className="mb-3 text-3xl">🧠</div><h3 className="text-lg font-bold">Use AI on your terms</h3><p className="mt-2 text-sm leading-6 text-slate-600 dark:text-slate-300">Generate clean ChatGPT prompts, paste back structured JSON, and compare roles by fit, gaps, priorities, and skills.</p></div><div className="premium-card p-5"><div className="mb-3 text-3xl">✅</div><h3 className="text-lg font-bold">Enjoy the process</h3><p className="mt-2 text-sm leading-6 text-slate-600 dark:text-slate-300">A beautiful dashboard, status shortcuts, application pace, follow-up timers, dark mode, and export/import reduce anxiety.</p></div></div></section></main>}
function ResetPassword(){const nav=useNavigate();const{uid,token}=useParams();const[password,setPassword]=useState('');const[err,setErr]=useState('');const[msg,setMsg]=useState('');async function sub(e:any){e.preventDefault();setErr('');try{const r=await api('/auth/password-reset/confirm/',{method:'POST',body:{uid,token,password}});setMsg(r.detail);setTimeout(()=>nav('/login'),1000)}catch(x:any){setErr(x.detail||'Reset failed')}}return <main className="mx-auto mt-20 max-w-sm rounded bg-white p-6 shadow"><h1 className="mb-4 text-2xl font-semibold">Set new password</h1><form onSubmit={sub} className="space-y-3"><PasswordInput placeholder="new password" invalid={!!err} value={password} onChange={e=>setPassword(e.target.value)}/><button>Reset password</button><SuccessMessage message={msg}/><ErrorBox error={err}/></form></main>}

function Onboarding(){const nav=useNavigate();function finish(){localStorage.removeItem('dachapply_onboarding_pending');nav('/',{replace:true})}const[step,setStep]=useState(1);const[profile,setProfile]=useState<any>({candidate_profile:'',target_roles:'',preferred_locations:''});const[job,setJob]=useState<any>({...empty,source:'onboarding'});const[loading,setLoading]=useState(true);const[saving,setSaving]=useState(false);const[err,setErr]=useState<any>(null);const[msg,setMsg]=useState('');useEffect(()=>{api('/profile/').then(p=>setProfile({...profile,...p})).catch(setErr).finally(()=>setLoading(false))},[]);async function saveProfile(){setErr(null);setSaving(true);try{await api('/profile/',{method:'PATCH',body:{candidate_profile:profile.candidate_profile,target_roles:profile.target_roles,preferred_locations:profile.preferred_locations}});setStep(2);setMsg('Profile saved. Now add one job so the dashboard has something to analyze.')}catch(e){setErr(e)}finally{setSaving(false)}}async function saveJob(skip=false){setErr(null);setSaving(true);try{if(!skip&&(job.url||job.company||job.title||job.raw_description)){await api('/jobs/',{method:'POST',body:{...job,duplicate_action:'duplicate'}});setMsg('First job added. You are ready to generate an analysis prompt.')}setStep(3)}catch(e){setErr(e)}finally{setSaving(false)}}const steps=['Profile','First job','Ready'];return <main className="mx-auto max-w-5xl px-4 py-8"><section className="premium-card overflow-hidden p-6 md:p-8"><div className="mb-6 flex flex-wrap items-start justify-between gap-4"><div><p className="mb-2 text-xs font-semibold uppercase tracking-[0.25em] text-blue-600 dark:text-blue-300">Quick setup</p><h1 className="text-3xl font-bold tracking-tight md:text-4xl">Make DACHApply useful in 2 minutes</h1><p className="mt-2 max-w-2xl text-sm leading-6 text-slate-600 dark:text-slate-300">Add your target profile and one job link. After that, your dashboard can prioritize roles, generate ChatGPT prompts, and track the application process.</p></div><button type="button" className="btn-muted" onClick={finish}>Skip setup</button></div><div className="mb-6 grid gap-2 sm:grid-cols-3">{steps.map((s,i)=><div key={s} className={(step===i+1?'border-blue-300 bg-blue-50 text-blue-900 dark:bg-blue-500/15 dark:text-blue-100':'border-slate-200 bg-white/60 text-slate-500 dark:border-white/10 dark:bg-white/5')+' rounded-2xl border px-4 py-3 text-sm font-semibold'}><span className="mr-2 inline-grid h-6 w-6 place-items-center rounded-full bg-slate-900 text-xs text-white dark:bg-white dark:text-slate-950">{i+1}</span>{s}</div>)}</div><Loading show={loading}/><ErrorBox error={err}/><SuccessMessage message={msg}/>{!loading&&step===1&&<div className="grid gap-4"><label className="block text-sm font-medium text-slate-700"><span>Your candidate profile / scoring rules</span><textarea className="mt-1" rows={10} value={profile.candidate_profile||''} onChange={e=>setProfile({...profile,candidate_profile:e.target.value})} placeholder="Paste your CV summary, target roles, strong skills, weaker fits, language level, salary/location preferences..."/></label><div className="grid gap-4 md:grid-cols-2"><input placeholder="Target roles, e.g. Python Backend, Data Engineer" value={profile.target_roles||''} onChange={e=>setProfile({...profile,target_roles:e.target.value})}/><input placeholder="Preferred locations, e.g. Vienna, Berlin, remote" value={profile.preferred_locations||''} onChange={e=>setProfile({...profile,preferred_locations:e.target.value})}/></div><div className="flex flex-wrap gap-2"><button type="button" className="btn-primary" disabled={saving} onClick={saveProfile}>{saving?'Saving…':'Save profile and continue'}</button><button type="button" className="btn-muted" onClick={()=>setStep(2)}>Do this later</button></div></div>}{!loading&&step===2&&<div className="grid gap-4"><div className="rounded-2xl border border-blue-100 bg-blue-50 p-4 text-sm text-blue-950 dark:border-blue-400/20 dark:bg-blue-500/10 dark:text-blue-100"><b>Tip:</b> Paste only a job URL if you want. You can enrich details later with the ChatGPT workflow.</div><input placeholder="Job URL" value={job.url} onChange={e=>setJob({...job,url:e.target.value})}/><div className="grid gap-4 md:grid-cols-2"><input placeholder="Company (optional)" value={job.company} onChange={e=>setJob({...job,company:e.target.value})}/><input placeholder="Role title (optional)" value={job.title} onChange={e=>setJob({...job,title:e.target.value})}/></div><textarea rows={5} placeholder="Paste job description text (optional)" value={job.raw_description} onChange={e=>setJob({...job,raw_description:e.target.value})}/><div className="flex flex-wrap gap-2"><button type="button" className="btn-primary" disabled={saving} onClick={()=>saveJob(false)}>{saving?'Adding…':'Add first job'}</button><button type="button" className="btn-muted" disabled={saving} onClick={()=>saveJob(true)}>Skip job for now</button></div></div>}{!loading&&step===3&&<div className="grid gap-4 md:grid-cols-3"><div className="rounded-2xl border p-4"><div className="mb-2 text-2xl">✅</div><h2 className="font-bold">Dashboard ready</h2><p className="mt-1 text-sm text-slate-600 dark:text-slate-300">Review priorities, statuses, follow-ups, and your application pace.</p></div><div className="rounded-2xl border p-4"><div className="mb-2 text-2xl">🧠</div><h2 className="font-bold">Analyze with ChatGPT</h2><p className="mt-1 text-sm text-slate-600 dark:text-slate-300">Select jobs in the dashboard and use “Analyze selected jobs” to get structured fit scores.</p></div><div className="rounded-2xl border p-4"><div className="mb-2 text-2xl">📌</div><h2 className="font-bold">Track outcomes</h2><p className="mt-1 text-sm text-slate-600 dark:text-slate-300">Move jobs through applied, interview, rejected, or archived and never miss follow-ups.</p></div><div className="md:col-span-3 flex flex-wrap gap-2"><button type="button" className="btn-primary" onClick={finish}>Open dashboard</button><Link className="btn" to="/add">Add another job</Link><Link className="btn-muted" to="/settings/profile">Edit profile later</Link></div></div>}</section></main>}

function GuidedOnboardingTour(){const nav=useNavigate();const loc=useLocation();const tourUser=storedUser();const userKey=String(tourUser?.username||'user');const userPendingKey='dachapply_onboarding_'+userKey+'_pending';const steps=[{path:'/',target:'profile-nav',action:'click',title:'1. Click Profile',body:'First teach DACHApply what a good job means for you. Click the highlighted Profile link in the navbar.'},{path:'/settings/profile',target:'profile-main',action:'input',title:'2. Paste your profile',body:'Paste a CV summary, target roles, preferred locations, languages, strengths, and red flags into the highlighted box. I will move on after you type/paste.'},{path:'/settings/profile',target:'profile-save',action:'click',wait:900,title:'3. Click Save profile',body:'Now click the highlighted Save profile button. Your future prompts and evaluations will use this profile.'},{path:'/',target:'add-job',action:'click',title:'4. Click + Add job',body:'Next add a real job. Click the highlighted + Add job button.'},{path:'/add',target:'job-links',action:'input',title:'5. Paste a job link',body:'Paste one or many job URLs into the highlighted box. One URL is enough to start.'},{path:'/add',target:'job-submit',action:'click',wait:1200,title:'6. Click Submit',body:'Click the highlighted Submit button to save the job. I will then bring you back to the dashboard.'},{path:'/',target:'first-job-row',action:'click',title:'7. Select one job',body:'Click the highlighted job row. Selecting a job reveals actions for analysis, status changes, and export.'},{path:'/',target:'analyze-selected',action:'click',wait:900,title:'8. Click Analyze selected jobs',body:'This opens the ChatGPT workflow and automatically copies a structured prompt to your clipboard.'},{path:'/',target:'prompt-response',action:'import',title:'9. Paste ChatGPT JSON response',body:'Paste the copied prompt into ChatGPT. Then paste ChatGPT JSON into this highlighted box. If it is valid JSON, DACHApply validates and imports it automatically.'},{path:'/',target:'prompt-close',action:'click',title:'10. Close the ChatGPT dialog',body:'After the import succeeds, close this dialog to return to the dashboard.'},{path:'/',target:'filters-action',action:'click',title:'11. Click Apply filters',body:'After at least one job is analyzed, filters help you focus by text, location, score, status, priority, or recommendation. Click Apply once.'},{path:'/',target:'bookmarklet-nav',action:'click',title:'12. Click Bookmarklet',body:'The Bookmarklet page shows how to install a one-click job saver so you can capture jobs while browsing. Click the highlighted Bookmarklet link.'},{path:'/bookmarklet',target:'bookmarklet-instructions',action:'read',title:'13. Install the bookmarklet',body:'Follow the highlighted page instructions: drag Save to DACHApply to your bookmarks bar, edit the bookmark URL, paste the bookmarklet code, and save. Press Next here when you understand the steps.'},{path:'/',target:'data-nav',action:'click',title:'14. Click Data',body:'Finally, click Data. This is where export/import and account deletion live.'},{path:'/export',target:'export-full',action:'click',title:'15. Export when needed',body:'This button exports everything. You now know the core workflow: profile, add jobs, analyze with ChatGPT, filter, save, and control your data.'}];const[started]=useState(()=>localStorage.getItem('dachapply_onboarding_pending')==='1');const saved=Number(localStorage.getItem('dachapply_onboarding_step')||'0');const[i,setI]=useState(started?Math.min(Math.max(saved,0),steps.length-1):-1);const[done,setDone]=useState<number[]>(()=>{try{return JSON.parse(localStorage.getItem('dachapply_onboarding_done')||'[]')}catch{return []}});const[pos,setPos]=useState<any>(null);const[stepFill,setStepFill]=useState(0);const step=steps[i];function persist(nextI:number,nextDone=done){localStorage.setItem('dachapply_onboarding_pending','1');localStorage.setItem(userPendingKey,'1');localStorage.setItem('dachapply_onboarding_step',String(Math.max(0,nextI)));localStorage.setItem('dachapply_onboarding_done',JSON.stringify(nextDone))}function finish(){localStorage.removeItem('dachapply_onboarding_pending');localStorage.removeItem(userPendingKey);localStorage.removeItem('dachapply_onboarding_step');localStorage.removeItem('dachapply_onboarding_done');localStorage.setItem('dachapply_onboarding_completed_'+userKey,'1');setI(-1);if((loc as any).state?.onboarding)nav(loc.pathname,{replace:true,state:{}})}function go(next:number){if(next>=steps.length){finish();return}setI(next);persist(next);if(loc.pathname!==steps[next].path)nav(steps[next].path)}function complete(idx=i){const nextDone=Array.from(new Set([...done,idx])).sort((a,b)=>a-b);setDone(nextDone);persist(idx,nextDone);return nextDone}function advance(){complete(i);go(i+1)}useEffect(()=>{function start(){localStorage.setItem('dachapply_onboarding_pending','1');localStorage.setItem(userPendingKey,'1');localStorage.setItem('dachapply_onboarding_step','0');localStorage.setItem('dachapply_onboarding_done','[]');setDone([]);setI(0)}window.addEventListener('dachapply_onboarding_start',start);if(i>=0){return()=>window.removeEventListener('dachapply_onboarding_start',start)}const pending=localStorage.getItem('dachapply_onboarding_pending')==='1'||localStorage.getItem(userPendingKey)==='1';const completed=localStorage.getItem('dachapply_onboarding_completed_'+userKey)==='1';if(pending||((loc as any).state?.onboarding&&!completed)){try{setDone(JSON.parse(localStorage.getItem('dachapply_onboarding_done')||'[]'))}catch{}setI(Math.min(Math.max(Number(localStorage.getItem('dachapply_onboarding_step')||'0'),0),steps.length-1));return()=>window.removeEventListener('dachapply_onboarding_start',start)}if(!tourUser||completed||['/login','/privacy','/terms'].some(x=>loc.pathname.startsWith(x))){return()=>window.removeEventListener('dachapply_onboarding_start',start)}api('/stats/').then(stats=>{if(Number(stats?.total_jobs||0)===0&&localStorage.getItem('dachapply_onboarding_completed_'+userKey)!=='1'){start()}}).catch(()=>{});return()=>window.removeEventListener('dachapply_onboarding_start',start)},[loc.pathname,userKey,i]);useEffect(()=>{if(step&&loc.pathname!==step.path)nav(step.path)},[i]);useEffect(()=>{if(!step)return;let dead=false;let cleanup=()=>{};function locate(){if(loc.pathname!==step.path)return;cleanup();cleanup=()=>{};setStepFill(0);const el=Array.from(document.querySelectorAll(`[data-tour="${step.target}"]`)).find((node:any)=>node.offsetParent!==null) as HTMLElement|null;if(!el){setPos(null);window.setTimeout(()=>{if(!dead)locate()},250);return}el.classList.add('tour-highlight');const onClick=()=>{if(step.action==='click'){const delay=Number((step as any).wait)||0;window.setTimeout(()=>advance(),delay)}};const inputFill=()=>{const v=(el as HTMLInputElement|HTMLTextAreaElement).value||'';return (step.action==='input'||step.action==='import')?Math.min(1,v.trim().length/10):0};setStepFill(inputFill());const onInput=()=>{const v=(el as HTMLInputElement|HTMLTextAreaElement).value||'';setStepFill(inputFill());if(step.action==='input'&&v.trim().length>10)window.setTimeout(()=>{if(!dead)advance()},450)};const onImportSuccess=()=>{if(step.action==='import')window.setTimeout(()=>{if(!dead)advance()},300)};el.addEventListener('click',onClick,true);el.addEventListener('input',onInput,true);el.addEventListener('change',onInput,true);window.addEventListener('dachapply_prompt_import_success',onImportSuccess);cleanup=()=>{el.classList.remove('tour-highlight');el.removeEventListener('click',onClick,true);el.removeEventListener('input',onInput,true);el.removeEventListener('change',onInput,true);window.removeEventListener('dachapply_prompt_import_success',onImportSuccess)};el.scrollIntoView({block:'center',inline:'center',behavior:'smooth'});window.setTimeout(()=>{if(dead)return;const targetRect=el.getBoundingClientRect();const rowRect=(step.target==='first-job-row'?((el.closest('tr,article') as HTMLElement|null)?.getBoundingClientRect()):null)||targetRect;const r=rowRect;const gap=16;const width=Math.min(390,window.innerWidth-24);const height=Math.min(360,window.innerHeight-24);const clamp=(v:number,min:number,max:number)=>Math.max(min,Math.min(v,max));let left:number,top:number;if(r.right+gap+width<=window.innerWidth){left=r.right+gap;top=clamp(r.top,12,window.innerHeight-height-12)}else if(r.left-gap-width>=0){left=r.left-gap-width;top=clamp(r.top,12,window.innerHeight-height-12)}else{left=clamp(targetRect.left,12,window.innerWidth-width-12);const below=r.bottom+gap;const above=r.top-gap-height;if(below+height<=window.innerHeight){top=below}else if(above>=12){top=above}else{top=r.top<window.innerHeight/2?Math.min(window.innerHeight-height-12,r.bottom+gap):12;if(top<r.bottom&&top+height>r.top)top=clamp(r.bottom+gap,12,window.innerHeight-height-12)}}setPos({left,top,width})},250)}locate();window.addEventListener('resize',locate);window.addEventListener('scroll',locate,true);return()=>{dead=true;cleanup();window.removeEventListener('resize',locate);window.removeEventListener('scroll',locate,true)}},[i,loc.pathname,done]);if(i<0||!step||!pos)return null;const progress=Math.min(100,Math.round(((done.length+stepFill)/steps.length)*100));return createPortal(<div className="pointer-events-none fixed inset-0 z-[9998] bg-slate-950/10"><div className="pointer-events-auto fixed max-h-[calc(100vh-1.5rem)] overflow-auto rounded-2xl border border-blue-200 bg-white p-4 text-slate-900 shadow-2xl ring-4 ring-blue-500/10 dark:border-cyan-300/30 dark:bg-slate-950 dark:text-slate-100" style={pos}><div className="mb-1 text-[11px] font-semibold uppercase tracking-[0.22em] text-blue-600 dark:text-cyan-300">Guided setup · {done.length}/{steps.length} done</div><h2 className="text-lg font-bold">{step.title}</h2><p className="mt-2 text-sm leading-6 text-slate-600 dark:text-slate-300">{step.body}</p><p className="mt-2 rounded-xl bg-blue-50 px-3 py-2 text-xs font-medium text-blue-900 dark:bg-cyan-400/10 dark:text-cyan-100">Do exactly this: {step.action==='input'?'click the highlighted field and paste/type your text.':step.action==='import'?'paste valid ChatGPT JSON here. I will continue only after it imports successfully.':step.action==='read'?'read the highlighted instructions, then press Next.':'click the highlighted button/link.'}</p><div className="mt-3 h-2 overflow-hidden rounded-full bg-slate-100 dark:bg-white/10"><div className="h-full rounded-full bg-blue-600 transition-all dark:bg-cyan-300" style={{width:`${progress}%`}}/></div><details className="mt-3 text-xs"><summary className="cursor-pointer font-semibold text-slate-500">Progress checklist</summary><ol className="mt-2 space-y-1">{steps.map((s,idx)=><li key={s.target} className={idx===i?'font-semibold text-blue-700 dark:text-cyan-200':done.includes(idx)?'text-green-700 dark:text-green-300':'text-slate-500'}>{done.includes(idx)?'✓':idx===i?'→':'•'} {s.title}</li>)}</ol></details><div className="mt-4 flex items-center justify-between gap-2"><button type="button" className="btn-muted" onClick={finish}>End tour</button><div className="flex items-center gap-2"><button type="button" className="btn" disabled={i===0} onClick={()=>go(Math.max(0,i-1))}>Back</button><button type="button" className="btn-primary" onClick={advance}>{i>=steps.length-1?'Finish':'Next'}</button></div></div></div></div>,document.body)}
