function intakePrefillFromLocation(loc:any){const rawHash=String(loc.hash||'');const params=new URLSearchParams(loc.search||((rawHash.startsWith('#?')||rawHash.startsWith('#'))?rawHash.replace(/^#\??/,'?'):''));const url=params.get('url')||params.get('u')||'';const title=params.get('title')||params.get('t')||'';const selected=params.get('selected_text')||params.get('selection')||params.get('text')||params.get('raw_description')||'';if(!url&&!title&&!selected)return null;return {...empty,source:'bookmarklet',url,title,raw_description:selected}}
function Bookmarklet(){const[origin,setOrigin]=useState('');const[copied,setCopied]=useState(false);useEffect(()=>setOrigin(window.location.origin),[]);const target=(origin||'')+'/add';const seedUrl=(origin||'')+'/bookmarklet';const code=`javascript:(()=>{const u=location.href,t=document.title,s=String(getSelection?getSelection():'');const q=new URLSearchParams({url:u,title:t,selected_text:s});window.open('${target}?'+q.toString(),'_blank','noopener');})();`;async function copy(){await navigator.clipboard.writeText(code);setCopied(true);window.setTimeout(()=>setCopied(false),2000)}return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-3xl font-semibold">Save-to-DACHApply bookmarklet</h1><p className="mb-4 text-slate-500">Create a browser bookmark. When you are on a job page, click it to open DACHApply's Add Job page prefilled with the current page URL, page title, and any selected text.</p><section data-tour="bookmarklet-instructions" className="rounded border p-4"><h2 className="mb-2 text-xl font-semibold">Install in Chrome</h2><ol className="list-decimal space-y-2 pl-5 text-sm text-slate-700"><li>Drag this normal DACHApply bookmark to your bookmarks bar: <a className="btn-primary inline-flex" href={seedUrl}>💾 Save to DACHApply</a></li><li>Wait until Chrome shows the DACHApply favicon on that bookmark.</li><li>Right-click the bookmark → <b>Edit</b>.</li><li>Replace its URL with the bookmarklet code below and save.</li><li>If Chrome removes the favicon after editing, rename the bookmark to <b>💾 Save to DACHApply</b> so it remains easy to spot.</li></ol><button data-tour="bookmarklet-copy" className="btn mt-3" onClick={copy}>{copied?'Copied':'Copy bookmarklet code'}</button><textarea className="mt-3 font-mono text-xs" rows={7} readOnly value={code}/></section><section className="mt-4 rounded bg-yellow-50 p-4 text-sm text-yellow-950"><b>Favicon limitation:</b> Chrome controls bookmarklet icons. A bookmarklet URL starts with <code>javascript:</code>, so Chrome may remove the favicon as soon as you paste the code. The app cannot force Chrome to keep it; the emoji name is the reliable fallback.</section><section className="mt-4 rounded bg-blue-50 p-4 text-sm text-blue-950"><b>Usage:</b> On any job page, optionally select part of the description, then click the bookmarklet. It opens <code>/add</code> with the URL/title/text prefilled. No browser extension required.</section></div></main>}

function IntakeSummary({summary}:{summary:any}){if(!summary)return null;const created=summary.created||[];const updated=summary.updated||[];const skipped=summary.skipped||[];const rows=[...created.map((j:any)=>({kind:'Created',label:`${j.company||'Unknown company'} — ${displayJobTitle(j.title)}`})),...updated.map((j:any)=>({kind:'Updated',label:`${j.company||'Unknown company'} — ${displayJobTitle(j.title)}`})),...skipped.map((j:any)=>({kind:'Skipped',label:j.url||`Link #${j.index+1}`}))];return <SuccessMessage title="Intake summary"><div className="text-sm">Created {created.length}, updated {updated.length}, skipped {skipped.length}.</div>{rows.length>0&&<ul className="mt-2 list-disc space-y-1 pl-5 text-sm">{rows.map((r:any,i:number)=><li key={i}><b>{r.kind}:</b> {r.label}</li>)}</ul>}</SuccessMessage>}

function JobForm({publicMode=false}:{publicMode?:boolean}){const nav=useNavigate();const loc=useLocation();const prefill=!publicMode?intakePrefillFromLocation(loc):null;const draftKey=publicMode?'dachapply_public_submit_draft':'dachapply_add_job_draft';const[form,setForm]=useState<any>(()=>prefill||JSON.parse(localStorage.getItem(draftKey)||'null')||(publicMode?{...empty,submitted_by:'',submitter_reason:''}:empty));function set(v:any){setForm(v);localStorage.setItem(draftKey,JSON.stringify(v))}useEffect(()=>{if(prefill){setForm(prefill);localStorage.setItem(draftKey,JSON.stringify(prefill))}},[loc.search,loc.hash]);const[summary,setSummary]=useState<any>(null);const[err,setErr]=useState<any>(()=>JSON.parse(localStorage.getItem(draftKey+'_err')||'null'));const[duplicateActions,setDuplicateActions]=useState<any[]>(()=>JSON.parse(localStorage.getItem(draftKey+'_actions')||'[]'));const[loading,setLoading]=useState(false);const[promptLoading,setPromptLoading]=useState(false);const[quickPrompt,setQuickPrompt]=useState('');const[quickPromptCopied,setQuickPromptCopied]=useState(false);const[advanced,setAdvanced]=useState(false);const linkDraftRef=useRef((form.url||'')+'\n'+(form.raw_description||''));useEffect(()=>{const now=(form.url||'')+'\n'+(form.raw_description||'');if(now!==linkDraftRef.current){linkDraftRef.current=now;setErr(null);setDuplicateActions([]);localStorage.removeItem(draftKey+'_err');localStorage.removeItem(draftKey+'_actions')}},[form.url,form.raw_description]);useEffect(()=>{err?localStorage.setItem(draftKey+'_err',JSON.stringify(err)):localStorage.removeItem(draftKey+'_err')},[err]);useEffect(()=>{duplicateActions.length?localStorage.setItem(draftKey+'_actions',JSON.stringify(duplicateActions)):localStorage.removeItem(draftKey+'_actions')},[duplicateActions]);async function submitWith(extra:any={}){setErr(null);setSummary(null);setQuickPrompt('');setQuickPromptCopied(false);setLoading(true);const incoming=extra.duplicate_actions||[];const merged=[...duplicateActions.filter((a:any)=>!incoming.some((b:any)=>b.index===a.index)),...incoming];if(incoming.length)setDuplicateActions(merged);const body={...form,...extra,...((merged.length||extra.duplicate_actions)?{duplicate_actions:merged}:{})};try{const res=await api(publicMode?'/public/submit/':'/jobs/bulk-create/',{method:'POST',body});localStorage.removeItem(draftKey);localStorage.removeItem(draftKey+'_err');localStorage.removeItem(draftKey+'_actions');setDuplicateActions([]);setSummary(res); if(!publicMode&&!res?.count)nav('/')}catch(x:any){setErr(x)}finally{setLoading(false)}}const savedJobs=[...(summary?.created||[]),...(summary?.updated||[])].filter((j:any)=>j?.id);const savedIds=savedJobs.map((j:any)=>j.id);async function generateQuickPrompt(){if(!savedIds.length)return;setPromptLoading(true);setQuickPromptCopied(false);try{const r=await api('/prompts/combined/',{method:'POST',body:{job_ids:savedIds}});const prompt=r.generated_prompt||'';setQuickPrompt(prompt);try{await navigator.clipboard.writeText(prompt);setQuickPromptCopied(true)}catch{}}catch(e){setErr(e)}finally{setPromptLoading(false)}}async function copyQuickPrompt(){if(!quickPrompt)return;await navigator.clipboard.writeText(quickPrompt);setQuickPromptCopied(true)}async function sub(e:any){e.preventDefault();submitWith()}return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-2xl font-semibold">{publicMode?'Submit a job lead':'Add job'}</h1><p className="mb-5 text-slate-500">{publicMode?'Paste a link only, or add more details if you have them.':'Paste a job URL and save it instantly. Details and fit analysis can be generated in the next step.'}</p><form onSubmit={sub} className="grid gap-3">{publicMode&&<p className="rounded-lg bg-blue-50 p-3 text-sm text-blue-900">You can submit job links here. You will not get access to the private dashboard.</p>}<label className="text-sm font-medium">Paste links<textarea data-tour="job-links" rows={Math.max(3,(form.url||'').split('\n').length,Math.ceil((form.url||'').length/80))} placeholder="Paste one job URL here. You can also paste many links, separated by spaces or new lines." aria-invalid={!!err&&err?.type!=='duplicate_conflicts'} value={form.url||''} onChange={e=>set({...form,url:e.target.value})}/></label><details open={advanced} onToggle={e=>setAdvanced((e.currentTarget as HTMLDetailsElement).open)}><summary className="cursor-pointer rounded-lg border border-slate-200 bg-slate-50 px-3 py-2 text-sm font-medium text-slate-600">Advanced / optional details</summary><div className="mt-3 grid gap-3"><div className="grid gap-3 md:grid-cols-2"><input placeholder="Company (optional)" onChange={e=>set({...form,company:e.target.value})}/><input placeholder="Title (optional)" onChange={e=>set({...form,title:e.target.value})}/><input className="filter-input" placeholder="Location" onChange={e=>set({...form,location:e.target.value})}/><select onChange={e=>set({...form,work_mode:e.target.value})}>{workModes.map(x=><option key={x}>{x}</option>)}</select><input placeholder="Salary info" onChange={e=>set({...form,salary_info:e.target.value})}/><input placeholder="Language requirements" onChange={e=>set({...form,language_requirements:e.target.value})}/></div>{!publicMode&&<input placeholder="Source" onChange={e=>set({...form,source:e.target.value})}/>} {publicMode&&<><input placeholder="Your name" onChange={e=>set({...form,submitted_by:e.target.value})}/><textarea rows={Math.max(3,(form.submitter_reason||'').split('\n').length,Math.ceil((form.submitter_reason||'').length/80))} placeholder="Why do you think this fits?" value={form.submitter_reason||''} onChange={e=>set({...form,submitter_reason:e.target.value})}/></>}<textarea rows={Math.max(5,(form.raw_description||'').split('\n').length,Math.ceil((form.raw_description||'').length/80))} placeholder="Raw description / notes — you can paste multiple links here too" value={form.raw_description||''} onChange={e=>set({...form,raw_description:e.target.value})}/></div></details><p className="text-sm text-slate-500">Links like https-www.karriere.at-jobs-7794074 are accepted and normalized.</p><button data-tour="job-submit" disabled={loading}>{loading?'Saving…':publicMode?'Submit for friend':'Save job link'}</button><IntakeSummary summary={summary}/>{!publicMode&&summary?.count>0&&<section className="rounded-2xl border border-green-200 bg-green-50 p-4 text-green-950"><h2 className="font-semibold">Job saved</h2><p className="mt-1 text-sm">Next: generate an analysis prompt, paste it into ChatGPT, then import the JSON response to get fit scores and recommendations.</p><div className="mt-3 flex flex-wrap gap-2"><button type="button" className="btn-primary" disabled={promptLoading||!savedIds.length} onClick={generateQuickPrompt}>{promptLoading?'Generating…':quickPromptCopied?'Prompt copied':'Generate + copy prompt'}</button>{quickPrompt&&<button type="button" className="btn" onClick={copyQuickPrompt}>Copy prompt again</button>}<Link className="btn-muted" to="/">Open dashboard</Link></div>{quickPrompt&&<textarea className="mt-3 font-mono text-xs" rows={8} readOnly value={quickPrompt}/>}</section>}{err?.type==='duplicate_conflicts'?<PublicDuplicateResolver error={err} onSubmit={submitWith} onCancel={()=>setErr(null)} publicMode={publicMode}/>:<ErrorBox error={err}/>}</form></div></main>}

function PublicDuplicateResolver({error,onSubmit,onCancel,publicMode}:{error:any;onSubmit:(x:any)=>void;onCancel:()=>void;publicMode:boolean}){const conflicts=error.conflicts||[];function pick(e:any,index:number,action:string){e.preventDefault();e.stopPropagation();onSubmit({duplicate_actions:[{index,action}]})}return <div className="rounded border border-yellow-200 bg-yellow-50 p-3 text-yellow-950"><b>{conflicts.length} duplicate link{conflicts.length===1?'':'s'} found.</b><p className="text-sm">These links already exist. {publicMode?'You can create duplicates or skip them.':'Choose what to do.'}</p><div className="mt-2 flex flex-wrap gap-2"><button type="button" onClick={()=>onSubmit({duplicate_strategy:'duplicate'})}>Duplicate all</button><button type="button" onClick={()=>onSubmit({duplicate_strategy:'skip'})}>Skip all</button>{!publicMode&&<button type="button" onClick={()=>onSubmit({duplicate_strategy:'override'})}>Override all</button>}<button type="button" className="bg-slate-500" onClick={onCancel}>Cancel</button></div>{conflicts.length>0&&<div className="mt-3 space-y-2">{conflicts.map((c:any)=><div key={c.index} className="flex items-center justify-between gap-3 rounded bg-white p-2"><a className="min-w-0 flex-1 break-all text-xs" href={hrefFor(c.url)} target="_blank" rel="noreferrer">{c.url}</a><span className="relative z-10 flex shrink-0 gap-1"><button type="button" title="Skip" className="btn-danger" onClick={e=>pick(e,c.index,'skip')}>✕ Skip</button><button type="button" title="Duplicate" className="btn-primary" onClick={e=>pick(e,c.index,'duplicate')}>⧉ Duplicate</button>{!publicMode&&<button type="button" title="Override" className="btn" onClick={e=>pick(e,c.index,'override')}>↻ Override</button>}</span></div>)}</div>}</div>}

function Detail(){const{id}=useParams();const[j,setJ]=useState<Job|null>(null);const[note,setNote]=useState('');const[loading,setLoading]=useState(true);const[err,setErr]=useState<any>(null);useEffect(()=>{api('/jobs/'+id+'/').then(setJ).catch(setErr).finally(()=>setLoading(false))},[id]);if(loading)return <Loading show/>;if(err)return <main className="p-6"><ErrorBox error={err}/></main>;if(!j)return <Empty>Job not found.</Empty>;let ev=j.latest_evaluation;return <main className="mx-auto max-w-5xl p-6"><Link to="/">← Dashboard</Link><div className="mt-4 rounded bg-white p-6 shadow-sm"><div className="flex flex-wrap items-start justify-between gap-4"><div><p className="text-sm text-slate-500">{j.company}</p><h1 className="text-3xl font-semibold">{j.url?<a href={hrefFor(j.url)} target="_blank" rel="noreferrer">{displayJobTitle(j.title)}</a>:displayJobTitle(j.title)}</h1><p className="mt-2 text-slate-600">{cleanDisplayLocation(j.location)||'Unknown location'}{workModeLabel(j.work_mode)?` · ${workModeLabel(j.work_mode)}`:''}</p></div><div className="flex gap-2"><Badge tone={statusTone(j.status)}>{j.status}</Badge>{ev&&<Badge tone={priorityTone(ev.priority)}>{ev.priority}</Badge>}{ev&&<Badge tone={recTone(ev.recommendation)}>{ev.recommendation}</Badge>}</div></div></div>{ev?<section className="mt-4 grid gap-4 md:grid-cols-3"><div className="rounded bg-white p-5 shadow-sm"><div className="text-sm text-slate-500">Fit score</div><div className="text-4xl font-semibold">{ev.fit_score}</div><p className="mt-2">{ev.summary}</p></div><div className="rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Main matches</h2><ul className="mt-2 list-disc pl-5 text-slate-700">{ev.main_match_reasons.map((x,i)=><li key={i}>{x}</li>)}</ul></div><div className="rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Main gaps</h2><ul className="mt-2 list-disc pl-5 text-slate-700">{ev.main_gaps.map((x,i)=><li key={i}>{x}</li>)}</ul></div><div className="rounded bg-white p-5 shadow-sm md:col-span-3"><h2 className="font-semibold">Next action</h2><p>{ev.next_action}</p><div className="mt-4 grid gap-4 md:grid-cols-3"><p><b>CV:</b> {ev.cv_adjustment_notes}</p><p><b>Interview:</b> {ev.interview_prep_notes}</p><p><b>Risk:</b> {ev.risk_notes}</p></div></div></section>:<div className="mt-4"><Empty>No evaluation yet. Generate a prompt from the Prompts page.</Empty></div>}<section className="mt-4 rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Description</h2><pre className="mt-2 whitespace-pre-wrap text-sm text-slate-700">{j.raw_description||'No description yet.'}</pre></section><section className="mt-4 rounded bg-white p-5 shadow-sm"><h2 className="font-semibold">Add note</h2><div className="mt-2 flex gap-2"><input placeholder="note" onChange={e=>setNote(e.target.value)}/><button onClick={()=>api('/jobs/'+id+'/notes/',{method:'POST',body:{note,note_type:'general'}})}>Save</button></div></section></main>}

function Prompts(){const[jobs,setJobs]=useState<Job[]>([]);const[ids,setIds]=useState<number[]>([]);const[p,setP]=useState('');const[links,setLinks]=useState('');const[loading,setLoading]=useState(true);const[err,setErr]=useState<any>(null);const[msg,setMsg]=useState('');useEffect(()=>{api('/jobs/').then(setJobs).catch(setErr).finally(()=>setLoading(false))},[]);const selected=useMemo(()=>jobs.filter(j=>ids.includes(j.id)),[jobs,ids]);async function gen(path:string,body:any){setErr(null);setMsg('');try{setP((await api(path,{method:'POST',body})).generated_prompt)}catch(e){setErr(e)}}return <main className="mx-auto max-w-6xl p-6"><h1 className="text-3xl font-semibold">Prompt generator</h1><p className="mb-4 text-slate-500">Prepare prompts manually, paste them into ChatGPT, then import JSON results.</p><ErrorBox error={err}/><section className="mb-4 rounded bg-white p-5 shadow-sm"><h2 className="text-xl font-semibold">Bulk links → details + evaluations</h2><textarea className="mt-3" rows={5} placeholder="Paste one job link per line" onChange={e=>setLinks(e.target.value)}/><button className="mt-3" onClick={()=>gen('/prompts/bulk-links/',{links})}>Generate Bulk Links Prompt</button></section><section className="grid gap-4 md:grid-cols-2"><div className="rounded bg-white p-5 shadow-sm"><h2 className="mb-3 text-xl font-semibold">Select existing jobs</h2><Loading show={loading}/>{!loading&&jobs.length===0&&<Empty>No jobs yet.</Empty>}<div className="max-h-96 space-y-2 overflow-auto">{jobs.map(j=><label key={j.id} className="flex gap-3 rounded border p-3 hover:bg-slate-50"><input type="checkbox" checked={ids.includes(j.id)} onChange={e=>setIds(e.target.checked?[...ids,j.id]:ids.filter(x=>x!==j.id))}/><span><b>#{j.id} {j.company}</b><br/><span className="text-slate-600">{displayJobTitle(j.title)}</span></span></label>)}</div><div className="mt-4 flex flex-wrap gap-2"><button disabled={!ids.length} onClick={()=>gen('/prompts/generate/',{job_ids:ids})}>Generate Evaluation Prompt</button><button disabled={!ids.length} onClick={()=>gen('/prompts/enrich/',{job_ids:ids})}>Generate Missing Details Prompt</button></div></div><div className="rounded bg-white p-5 shadow-sm"><h2 className="mb-3 text-xl font-semibold">Selected preview</h2>{selected.length===0?<p className="text-slate-500">No jobs selected.</p>:selected.map(j=><div key={j.id} className="mb-2 rounded bg-slate-50 p-3"><b>#{j.id} {j.company}</b><div>{displayJobTitle(j.title)}</div><div className="text-xs text-slate-500">{[cleanDisplayLocation(j.location),workModeLabel(j.work_mode),j.url].filter(Boolean).join(' · ')}</div></div>)}</div></section><section className="mt-4 rounded bg-white p-5 shadow-sm"><div className="mb-2 flex items-center justify-between"><h2 className="text-xl font-semibold">Generated prompt</h2><button disabled={!p} onClick={async()=>{await navigator.clipboard.writeText(p);setMsg('Copied to clipboard')}}>Copy to clipboard</button></div><SuccessMessage message={msg} compact/><textarea rows={20} value={p} onChange={e=>setP(e.target.value)} placeholder="Generated prompt appears here…"/></section></main>}

function DuplicateResolver({error,jsonText,onDone}:{error:any;jsonText:string;onDone:(r:any)=>void}){const[actions,setActions]=useState<Record<number,string>>({});if(error?.type!=='duplicate_conflicts'&&error?.type!=='evaluation_conflicts')return <ErrorBox error={error}/>;async function submit(strategy?:string){const data=JSON.parse(jsonText);if(strategy)data.duplicate_strategy=strategy;else data.duplicate_actions=error.conflicts.map((c:any)=>({index:c.index,action:actions[c.index]||'skip'}));const res=await api('/evaluations/import/',{method:'POST',body:{json:JSON.stringify(data)}});onDone(res)}return <div className="rounded border border-yellow-200 bg-yellow-50 p-4 text-yellow-950"><h3 className="font-semibold">{error.type==='evaluation_conflicts'?'Existing evaluations found':'Duplicate jobs found'}</h3><p className="mb-3 text-sm">{error.type==='evaluation_conflicts'?'Some selected jobs already have evaluations. Choose whether to override, duplicate, skip, or abort.':'Some imported jobs already exist. Choose one action for all jobs, or decide per job.'}</p><div className="mb-3 flex flex-wrap gap-2"><button onClick={()=>submit('override')}>Override all</button><button onClick={()=>submit('duplicate')}>Duplicate all</button><button onClick={()=>submit('skip')}>Skip all</button><button className="bg-slate-500" onClick={()=>onDone({ok:false,aborted:true,message:'Import aborted'})}>Abort</button></div><div className="space-y-2">{error.conflicts.map((c:any)=><div key={c.index} className="rounded bg-white p-3"><div className="font-medium">{error.type==='evaluation_conflicts'?`Job #${c.job_id} already has an evaluation`:`Incoming: ${c.incoming.company} — ${c.incoming.title}`}</div>{c.url&&<div className="text-xs text-slate-600">URL: {c.url}</div>}<div className="text-xs text-slate-600">Existing: {c.existing_jobs?c.existing_jobs.map((j:any)=>`#${j.id} ${j.company} — ${displayJobTitle(j.title)}`).join('; '):c.existing_evaluations?.map((ev:any)=>`#${ev.id} ${ev.fit_score}% ${ev.priority} ${ev.recommendation}`).join('; ')}</div><select className="mt-2 max-w-xs" value={actions[c.index]||'skip'} onChange={e=>setActions({...actions,[c.index]:e.target.value})}><option value="skip">Skip this job</option><option value="override">Override existing</option><option value="duplicate">{error.type==='evaluation_conflicts'?'Add another evaluation':'Create duplicate with (1)'}</option></select></div>)}</div><button className="mt-3" onClick={()=>submit()}>Apply per-job choices</button></div>}

function ImportEval(){const[t,setT]=useState('');const[r,setR]=useState<any>(null);const[err,setErr]=useState<any>(null);const[loading,setLoading]=useState(false);async function submit(){setLoading(true);setErr(null);setR(null);try{setR(await api('/evaluations/import/',{method:'POST',body:{json:t}}))}catch(e){setErr(e)}finally{setLoading(false)}}return <main className="mx-auto max-w-5xl p-6"><h1 className="text-3xl font-semibold">Import ChatGPT JSON</h1><p className="mb-4 text-slate-500">Paste evaluation JSON, job_updates JSON, or bulk jobs JSON.</p><textarea rows={18} placeholder="Paste JSON here" aria-invalid={!!err} onChange={e=>setT(e.target.value)} /><button className="mt-3" disabled={loading||!t.trim()} onClick={submit}>{loading?'Importing…':'Validate and Import'}</button>{err&&<div className="mt-4"><h2 className="font-semibold text-red-700">Validation errors</h2><DuplicateResolver error={err} jsonText={t} onDone={(res:any)=>{setErr(null);setR(res)}}/></div>}{r&&<div className="mt-4"><ImportResultSummary result={r}/></div>}</main>}

function Followups(){const[fs,setFs]=useState<FollowUp[]>([]);const[loading,setLoading]=useState(true);const[err,setErr]=useState<any>(null);async function load(){api('/followups/').then(setFs).catch(setErr).finally(()=>setLoading(false))}useEffect(()=>{load()},[]);let today=new Date().toISOString().slice(0,10);return <main className="mx-auto max-w-4xl p-6"><h1 className="text-3xl font-semibold">Follow-ups</h1><ErrorBox error={err}/><Loading show={loading}/>{!loading&&fs.length===0&&<Empty>No follow-ups yet.</Empty>}{fs.map(f=><div key={f.id} className={(f.follow_up_date<today&&!f.completed?'border-red-200 bg-red-50':'bg-white')+' my-2 rounded border p-4 shadow-sm'}><b>{f.follow_up_date}</b> {f.company} — {f.title}<p>{f.reason}</p>{!f.completed&&<button onClick={async()=>{await api('/followups/'+f.id+'/',{method:'PATCH',body:{completed:true}});load()}}>Mark completed</button>}</div>)}</main>}
function ProfileSettings(){
const emptyProfile:CandidateProfile={candidate_profile:'',target_roles:'',preferred_locations:'',salary_expectations:'',language_levels:'',preferred_stack:'',red_flags:'',selling_points:'',evaluation_prompt_template:'',combined_prompt_template:'',enrichment_prompt_template:'',bulk_links_prompt_template:''};
const[form,setForm]=useState<CandidateProfile>(emptyProfile);
const[loading,setLoading]=useState(true);
const[saving,setSaving]=useState(false);
const[err,setErr]=useState<any>(null);
const[msg,setMsg]=useState('');
const[cvText,setCvText]=useState('');
const[cvPrompt,setCvPrompt]=useState('');
const[generatedProfile,setGeneratedProfile]=useState('');
const[cvMsg,setCvMsg]=useState('');
useEffect(()=>{api('/profile/').then(setForm).catch(setErr).finally(()=>setLoading(false))},[]);
async function save(e:any){e.preventDefault();setSaving(true);setErr(null);setMsg('');try{const saved=await api('/profile/',{method:'PATCH',body:form});setForm(saved);setMsg('Profile saved. Future generated prompts will use this text and any custom templates.')}catch(x){setErr(x)}finally{setSaving(false)}}
function buildCvPrompt(text:string){return `You are helping create a private candidate profile for DACHApply, a job matching and application tracking tool.

TASK
Analyze the CV text below and produce a concise, honest candidate profile that can be reused for evaluating job postings.

IMPORTANT RULES
- Do not invent experience, employers, education, certifications, technologies, years of experience, languages, or seniority.
- If something is unclear, write it as uncertain or omit it.
- Be honest about gaps and weaker-fit roles.
- Prefer concrete evidence from the CV over generic strengths.
- Keep the result useful for comparing the candidate against software/tech job descriptions.

OUTPUT FORMAT
Return only the profile text, with these sections:

1. Candidate summary
2. Strongest target roles
3. Weaker-fit / lower-priority roles
4. Core technical skills
5. Domain and project experience
6. Languages and location/work preferences, if visible
7. Selling points to emphasize
8. Red flags / gaps / hiring risks
9. Job matching rules
   - What to reward highly
   - What to penalize
   - Maximum score guidance for roles with major gaps
10. Short final candidate_profile paragraph suitable to paste into DACHApply

CV TEXT
${text.trim()}`}
function stripCvMetadata(text:string,isLatex=false){let t=text.replace(/^\uFEFF/,'').replace(/^---\s*\n[\s\S]*?\n---\s*(?:\n|$)/,'').replace(/^\+\+\+\s*\n[\s\S]*?\n\+\+\+\s*(?:\n|$)/,'').replace(/<!--[\s\S]*?-->/g,'');if(isLatex){t=t.replace(/[\s\S]*?\\begin\{document\}/,'').replace(/\\end\{document\}[\s\S]*/,'').replace(/\\(?:hypersetup|pdfinfo)\s*\{[\s\S]*?\}\s*/g,'').replace(/\\(?:title|author|date|thanks|subject|keywords)\*?(?:\[[^\]]*\])?\s*\{[^{}]*\}\s*/g,'').replace(/^\s*\\(?:documentclass|usepackage|geometry|pagestyle|thispagestyle|newcommand|renewcommand|def|setlength|input|include)\b.*$/gmi,'')}const meta=/^\s*(?:title|author|date|subject|keywords|creator|producer|generator|created|modified|last modified|revision|template|source|pdfauthor|pdftitle|pdfsubject|pdfkeywords)\s*[:=].*$/i;return t.split('\n').filter((line,i)=>!(i<80&&meta.test(line))).join('\n')}
function cleanLatexCv(text:string){return stripCvMetadata(text,true).replace(/%.*$/gm,'').replace(/\\(?:section|subsection|subsubsection|paragraph|textbf|textit|emph|item)\*?\s*\{([^{}]*)\}/g,'$1\n').replace(/\\(?:begin|end)\{[^}]+\}/g,'\n').replace(/\\[a-zA-Z]+\*?(?:\[[^\]]*\])?(?:\{([^{}]*)\})?/g,(_m,inner)=>inner?`${inner} `:' ').replace(/[{}]/g,' ').replace(/[ \t]+/g,' ').replace(/\n{3,}/g,'\n\n').trim()}
function normalizeCvLine(line:string){return line.replace(/\$\\?\|\$/g,' | ').replace(/\\([&%#$])/g,'$1').replace(/\\\\(?:\[[^\]]*\])?/g,' ').replace(/\b([A-ZÄÖÜ][\p{L}.'-]+(?:\s+[A-ZÄÖÜ][\p{L}.'-]+){0,3}),\s*(?:Austria|Germany|Switzerland|Hungary|Greece|Netherlands|France|Spain|Italy|Portugal|Poland|Czechia|Czech Republic|Slovakia|Slovenia|Romania|Bulgaria|Belgium|Denmark|Sweden|Norway|Finland|Ireland|United Kingdom|UK|USA|United States)\b/giu,'$1').replace(/\s+[-+]?\d+(?:\.\d+)?\s*(?:pt|em|ex|in|cm|mm)\s*$/i,'').replace(/\s+[|&]\s*$/,'').replace(/[ \t]+/g,' ').trim()}
function isCvNoiseLine(line:string){return /^(?:[xXlcrpmb@{}>|<\s]+|&|\[[a-z]\]\s*\d*(?:\.\d+)?)$/i.test(line)||/^\[[^\]]*(?:leftmargin|label|itemsep|topsep|parsep|margin)[^\]]*\]$/i.test(line)||/^[-+]?\d+(?:\.\d+)?\s*(?:pt|em|ex|in|cm|mm)$/i.test(line)||/^\.?\/?[\w .-]+\.(?:jpe?g|png|gif|webp|svg|pdf)$/i.test(line)||/(?:mailto:|https?:\/\/|www\.|linkedin\.com|github\.com|\.github\.io)/i.test(line)||/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i.test(line)||/^\+?\d[\d\s().-]{7,}\d$/.test(line)}
function compactCvText(text:string){return stripCvMetadata(text).replace(/\r\n?/g,'\n').split('\n').map(normalizeCvLine).filter(line=>line.length>0&&!isCvNoiseLine(line)).join('\n').trim()}
async function writeCvPromptToClipboard(prompt:string){try{await navigator.clipboard.writeText(prompt);return true}catch{return false}}
async function generateAndCopyCvPrompt(text=cvText,source=''){setCvMsg('');const compacted=compactCvText(text);if(!compacted){setCvMsg('Paste or drop CV text first.');return}setCvText(compacted);const prompt=buildCvPrompt(compacted);setCvPrompt(prompt);const saved=Math.max(0,text.length-compacted.length);const copied=await writeCvPromptToClipboard(prompt);setCvMsg(`${source?`Loaded ${source}. `:''}Metadata and extra spaces removed${saved?` (${saved} characters saved)`:''}. ChatGPT prompt generated${copied?' and copied to clipboard.':' but clipboard copy was blocked; use the Copy prompt button.'}`)}
function generateCvPrompt(){generateAndCopyCvPrompt()}
async function copyCvPrompt(){if(!cvPrompt)return;const copied=await writeCvPromptToClipboard(cvPrompt);setCvMsg(copied?'CV prompt copied to clipboard.':'Clipboard copy was blocked by the browser.')} 
async function loadCvFile(file?:File){if(!file)return;setCvMsg('');const lower=file.name.toLowerCase();if(!lower.endsWith('.txt')&&!lower.endsWith('.md')&&!lower.endsWith('.text')&&!lower.endsWith('.tex')&&!lower.endsWith('.latex')&&!lower.endsWith('.ltx')){setCvMsg('For now, paste PDF/DOCX CV text manually or drop a .txt/.md/.tex/.latex version.');return}const raw=await file.text();const text=(lower.endsWith('.tex')||lower.endsWith('.latex')||lower.endsWith('.ltx'))?(cleanLatexCv(raw)||raw):raw;await generateAndCopyCvPrompt(text,file.name)}
const field=(key:keyof CandidateProfile,label:string,help:string,rows=3)=><label className="block text-sm font-medium text-slate-700"><span>{label}</span><textarea data-tour={key==='candidate_profile'?'profile-main':undefined} className="mt-1" rows={rows} value={form[key]||''} onChange={e=>setForm({...form,[key]:e.target.value})}/><span className="mt-1 block text-xs font-normal text-slate-500">{help}</span></label>;
const templateHelp='Optional. Leave blank to use the app default. Available placeholders: {candidate_profile}, {recommendation_rules}, {skill_analysis_rules}, {custom_instructions_section}, {schema}, and {jobs} or {links}.';
return <main className="mx-auto max-w-5xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-3xl font-semibold">Candidate profile</h1><p className="mb-5 text-slate-500">Keep this simple: paste the candidate's full profile, scoring rules, fit guidance, and red flags into one box. The optional sections below are only for power users.</p><Loading show={loading}/><ErrorBox error={err}/>{!loading&&<form onSubmit={save} className="grid gap-4"><section className="rounded border p-4"><h2 className="mb-3 text-xl font-semibold">CV → candidate profile helper</h2><p className="mb-3 text-sm text-slate-500">Privacy-first workflow: paste or drop a CV text/Markdown/LaTeX file; the ChatGPT prompt is generated and copied automatically, then you can paste the result back here. The CV file itself is not uploaded by this form.</p><label onDragOver={e=>e.preventDefault()} onDrop={e=>{e.preventDefault();loadCvFile(e.dataTransfer.files?.[0])}} className="mb-3 block cursor-pointer rounded border border-dashed border-slate-300 bg-slate-50 p-5 text-center text-sm text-slate-600 hover:bg-slate-100"><b>Drop a .txt/.md/.tex CV here</b><br/>or click anywhere in this box to choose a text, Markdown, or LaTeX file. For PDF/DOCX, copy the text manually for now.<input className="hidden" type="file" accept=".txt,.md,.text,.tex,.latex,.ltx,text/plain,text/markdown,text/x-tex,application/x-tex" onChange={e=>loadCvFile(e.target.files?.[0]||undefined)}/></label><textarea rows={8} value={cvText} onChange={e=>setCvText(e.target.value)} placeholder="Paste CV text here…"/><div className="mt-3 flex flex-wrap gap-2"><button type="button" onClick={generateCvPrompt}>Clean + generate + copy ChatGPT prompt</button><button type="button" className="btn-muted" disabled={!cvText.trim()} onClick={()=>{const cleaned=compactCvText(cvText);setCvText(cleaned);setCvMsg('Metadata and extra spaces removed from CV text.')}}>Remove metadata/spaces</button><button type="button" className="btn-muted" disabled={!cvPrompt} onClick={copyCvPrompt}>Copy prompt again</button><button type="button" className="btn-muted" onClick={()=>{setCvText('');setCvPrompt('');setGeneratedProfile('');setCvMsg('Cleared CV helper.')}}>Clear helper</button></div>{cvMsg&&<div className="mt-3 rounded bg-blue-50 p-2 text-sm text-blue-900">{cvMsg}</div>}{cvPrompt&&<div className="mt-4 grid gap-3"><label className="block text-sm font-medium text-slate-700">Generated prompt<textarea className="mt-1" rows={12} value={cvPrompt} onChange={e=>setCvPrompt(e.target.value)}/></label><label className="block text-sm font-medium text-slate-700">Paste ChatGPT result here<textarea className="mt-1" rows={8} value={generatedProfile} onChange={e=>setGeneratedProfile(e.target.value)} placeholder="Paste the generated candidate profile from ChatGPT…"/></label><button type="button" className="btn-muted" disabled={!generatedProfile.trim()} onClick={()=>{setForm({...form,candidate_profile:generatedProfile});setCvMsg('Generated profile copied into Candidate profile. Review it, then save.')}}>Use result as candidate profile</button></div>}</section><section className="rounded border p-4"><h2 className="mb-3 text-xl font-semibold">Profile text sent to ChatGPT</h2>{field('candidate_profile','Candidate profile / scoring rules','Paste the full candidate profile here. You can include experience, strongest fits, weaker fits, salary, languages, calibration rules, penalty caps, and instructions like “do not invent experience”.',16)}</section><details className="rounded border p-4"><summary className="cursor-pointer text-xl font-semibold">Advanced structured fields (optional)</summary><p className="mt-2 text-sm text-slate-500">Leave these blank unless you want the app to append labeled sections to the main profile text.</p><div className="mt-4 grid gap-4 md:grid-cols-2"><div className="rounded border p-4">{field('target_roles','Target roles','Optional target roles.')}</div><div className="rounded border p-4">{field('preferred_locations','Preferred locations','Optional location preferences.')}</div><div className="rounded border p-4">{field('salary_expectations','Salary expectations','Optional salary notes.')}</div><div className="rounded border p-4">{field('language_levels','Language levels','Optional language notes.')}</div><div className="rounded border p-4">{field('preferred_stack','Preferred stack','Optional technologies to reward.')}</div><div className="rounded border p-4">{field('red_flags','Red flags','Optional deal-breakers or weak-fit areas.')}</div><div className="rounded border p-4 md:col-span-2">{field('selling_points','Selling points','Optional strengths to surface in CV/interview advice.',4)}</div></div></details><details className="rounded border p-4"><summary className="cursor-pointer text-xl font-semibold">Prompt templates (optional)</summary><p className="mt-2 text-sm text-slate-500">Generated prompts remain visible before copying. Customize these only if you want to change the reusable prompt wording; leave blank to use the app defaults.</p><div className="mt-4 grid gap-4">{field('combined_prompt_template','Missing details + evaluation template',templateHelp,10)}{field('evaluation_prompt_template','Evaluation-only template',templateHelp,8)}{field('enrichment_prompt_template','Missing details-only template',templateHelp,8)}{field('bulk_links_prompt_template','Bulk links template',templateHelp.replace('{jobs} or {links}','{links}'),8)}</div></details><div className="flex flex-wrap items-center gap-3"><button data-tour="profile-save" disabled={saving}>{saving?'Saving…':'Save profile'}</button><SuccessMessage message={msg} compact/></div></form>}</div></main>}

function AccountDeletion(){const nav=useNavigate();const[password,setPassword]=useState('');const[confirm,setConfirm]=useState('');const[err,setErr]=useState<any>(null);const[loading,setLoading]=useState(false);async function deleteAccount(){setErr(null);if(confirm!=='DELETE'){setErr('Type DELETE to confirm account deletion.');return}setLoading(true);try{await api('/auth/account/',{method:'DELETE',body:{password,confirm}});Object.keys(localStorage).filter(k=>k.startsWith('dachapply_')).forEach(k=>localStorage.removeItem(k));nav('/login',{replace:true})}catch(e){setErr(e)}finally{setLoading(false)}}return <section className="mt-6 rounded border border-red-200 bg-red-50 p-4"><h2 className="mb-2 text-xl font-semibold text-red-950">Delete account</h2><p className="mb-3 text-sm text-red-900">Permanently deletes your account, candidate profile, owned jobs, evaluations, notes, and follow-ups. Export your data first if you want a copy.</p><div className="grid gap-2 md:grid-cols-2"><PasswordInput placeholder="Current password" invalid={!!err&&String(messageText(err)).toLowerCase().includes('password')} value={password} onChange={e=>setPassword(e.target.value)}/><input placeholder="Type DELETE to confirm" aria-invalid={!!err&&String(messageText(err)).toLowerCase().includes('delete')} value={confirm} onChange={e=>setConfirm(e.target.value)}/></div><div className="mt-3 flex flex-wrap items-center gap-3"><button type="button" className="btn-danger" disabled={loading} onClick={deleteAccount}>{loading?'Deleting…':'Delete my account'}</button><span className="text-xs text-red-900">This cannot be undone.</span></div><div className="mt-3"><ErrorBox error={err}/></div></section>}
function ChangePassword(){const[form,setForm]=useState<any>({current_password:'',new_password:'',confirm_password:''});const[err,setErr]=useState<any>(null);const[msg,setMsg]=useState('');const[loading,setLoading]=useState(false);async function submit(e:any){e.preventDefault();setErr(null);setMsg('');if(form.new_password!==form.confirm_password){setErr('New passwords do not match.');return}setLoading(true);try{const r=await api('/auth/change-password/',{method:'POST',body:{current_password:form.current_password,new_password:form.new_password}});setMsg(r.detail||'Password updated.');setForm({current_password:'',new_password:'',confirm_password:''})}catch(x:any){setErr(x?.detail||'Password update failed. Please check your current password and try again.')}finally{setLoading(false)}}return <section className="mt-6 rounded border p-4"><h2 className="mb-2 text-xl font-semibold">Change password</h2><p className="mb-3 text-sm text-slate-600">Set a new password for this account.</p><form onSubmit={submit} className="grid gap-3"><PasswordInput autoComplete="current-password" placeholder="Current password" invalid={!!err&&String(messageText(err)).toLowerCase().includes('current password')} value={form.current_password} onChange={e=>setForm({...form,current_password:e.target.value})}/><div className="grid gap-3 md:grid-cols-2"><PasswordInput autoComplete="new-password" placeholder="New password" invalid={!!err&&(String(messageText(err)).toLowerCase().includes('new password')||String(messageText(err)).toLowerCase().includes('passwords do not match'))} value={form.new_password} onChange={e=>setForm({...form,new_password:e.target.value})}/><PasswordInput autoComplete="new-password" placeholder="Confirm new password" invalid={!!err&&(String(messageText(err)).toLowerCase().includes('new password')||String(messageText(err)).toLowerCase().includes('passwords do not match'))} value={form.confirm_password} onChange={e=>setForm({...form,confirm_password:e.target.value})}/></div><div className="flex flex-wrap items-center gap-3"><button type="submit" className="btn-primary" disabled={loading}>{loading?'Updating…':'Update password'}</button><SuccessMessage message={msg} compact/></div><ErrorBox error={err}/></form></section>}
function AccountSettings(){const nav=useNavigate();const user=storedUser();function restartGuide(){const key=String(user?.username||'user');localStorage.removeItem('dachapply_onboarding_completed_'+key);localStorage.setItem('dachapply_onboarding_pending','1');localStorage.setItem('dachapply_onboarding_'+key+'_pending','1');localStorage.setItem('dachapply_onboarding_step','0');localStorage.setItem('dachapply_onboarding_done','[]');window.dispatchEvent(new Event('dachapply_onboarding_start'));nav('/',{replace:false,state:{onboarding:true}})}return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-3xl font-semibold">Account settings</h1><p className="mb-5 text-slate-500">Manage account-level actions. Candidate profile settings are still available from the Profile page.</p><section className="rounded border p-4"><h2 className="mb-2 text-xl font-semibold">Guided setup</h2><p className="mb-3 text-sm text-slate-600">Restart the onboarding tour if you want a step-by-step walkthrough of the app again.</p><button type="button" className="btn-primary" onClick={restartGuide}>Restart guided setup</button></section><ChangePassword/><AccountDeletion/></div></main>}
function Export(){
  const[file,setFile]=useState<File|null>(null),[summary,setSummary]=useState<any>(null),[err,setErr]=useState<any>(null),[loading,setLoading]=useState(false),[dragging,setDragging]=useState(false),[open,setOpen]=useState<string|null>(null);
  const fileInputRef=useRef<HTMLInputElement|null>(null);
  function csrf(){return document.cookie.split('; ').find(r=>r.startsWith('csrftoken='))?.split('=')[1]}
  function preferences(){const prefs:any={theme:localStorage.getItem('dachapply_theme')||'light',hidden_columns:JSON.parse(localStorage.getItem('dachapply_hidden_cols')||'[]'),skill_overrides:JSON.parse(localStorage.getItem('dachapply_skill_overrides')||'{}'),work_mode_tones:JSON.parse(localStorage.getItem('dachapply_work_mode_tones')||'{}'),location_tones:JSON.parse(localStorage.getItem('dachapply_location_tones')||'{}')};for(let i=0;i<localStorage.length;i++){const key=localStorage.key(i)||'';if(key.startsWith('dachapply_')&&key!=='dachapply_user')prefs[key]=localStorage.getItem(key)}return prefs}
  function applyPreferences(prefs:any){if(!prefs||typeof prefs!=='object')return false;if(typeof prefs.theme==='string')localStorage.setItem('dachapply_theme',prefs.theme);if(Array.isArray(prefs.hidden_columns))localStorage.setItem('dachapply_hidden_cols',JSON.stringify(prefs.hidden_columns));if(prefs.skill_overrides&&typeof prefs.skill_overrides==='object')localStorage.setItem('dachapply_skill_overrides',JSON.stringify(prefs.skill_overrides));if(prefs.work_mode_tones&&typeof prefs.work_mode_tones==='object')localStorage.setItem('dachapply_work_mode_tones',JSON.stringify(prefs.work_mode_tones));if(prefs.location_tones&&typeof prefs.location_tones==='object')localStorage.setItem('dachapply_location_tones',JSON.stringify(prefs.location_tones));Object.entries(prefs).forEach(([k,v])=>{if(k.startsWith('dachapply_')&&k!=='dachapply_user')localStorage.setItem(k,String(v))});return true}
  function downloadBlob(blob:Blob,name:string){const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();URL.revokeObjectURL(a.href)}
  async function importFile(f?:File|null,strategy?:string){setErr(null);setSummary(null);if(!f)return;const name=f.name.toLowerCase();if(!name.endsWith('.json')&&!name.endsWith('.csv')&&!name.endsWith('.xlsx')){setFile(null);setErr('Please choose a JSON, CSV, or XLSX export file.');return}setFile(f);setLoading(true);try{let parsed:any=null;let importedPrefs:any=null;if(name.endsWith('.json')){try{parsed=JSON.parse(await f.text());importedPrefs=parsed.frontend_preferences||parsed.preferences}catch{}}const hasBackend=!!(parsed?.schema_version&&parsed?.app&&parsed?.data);if(name.endsWith('.json')&&importedPrefs&&!hasBackend){const ok=applyPreferences(importedPrefs);setSummary({created:{},updated:{},skipped:{},errors:[],preferences:ok?'imported':'none'});return}const body=new FormData();body.append('file',f);if(strategy)body.append('duplicate_strategy',strategy);const headers:any={};const token=csrf();if(token)headers['X-CSRFToken']=token;const res=await fetch('/api/import/',{method:'POST',credentials:'include',headers,body});const text=await res.text();const data=text?JSON.parse(text):{};if(!res.ok){if(data?.type==='import_conflicts')setSummary(data);else throw data;return}const prefs=data.frontend_preferences||importedPrefs;const ok=applyPreferences(prefs);setSummary(ok?{...data,preferences:'imported'}:data)}catch(e){setErr(e)}finally{setLoading(false);if(fileInputRef.current)fileInputRef.current.value=''}}
  async function exportKind(kind:'jobs'|'preferences'|'full',type:'json'|'csv'|'xlsx'){setErr(null);setOpen(null);try{const token=csrf();const headers:any={'Content-Type':'application/json'};if(token)headers['X-CSRFToken']=token;const res=await fetch('/api/export/',{method:'POST',credentials:'include',headers,body:JSON.stringify({kind,type,preferences:preferences()})});if(!res.ok)throw {detail:await res.text()};downloadBlob(await res.blob(),`dachapply-${kind}-${new Date().toISOString().slice(0,10)}.${type}`)}catch(e){setErr(e)}}
  function ExportChoice({id,label,icon}:{id:'jobs'|'preferences'|'full';label:string;icon:string}){return <span className="relative" onMouseEnter={()=>setOpen(id)} onMouseLeave={()=>setOpen(null)}><button data-tour={id==='full'?'export-full':undefined} className="btn-primary min-w-36 justify-center" onClick={()=>setOpen(open===id?null:id)} title={`${label}: choose JSON, CSV, or XLSX`}><span className="mr-1">{icon}</span>{label}</button>{open===id&&<div className="absolute left-0 top-full z-30 flex gap-1 rounded-2xl border border-slate-200 bg-white/95 p-2 text-slate-900 shadow-2xl ring-1 ring-slate-900/5 backdrop-blur"><button className="btn" onClick={()=>exportKind(id,'json')}>JSON</button><button className="btn" onClick={()=>exportKind(id,'csv')}>CSV</button><button className="btn" onClick={()=>exportKind(id,'xlsx')}>XLSX</button></div>}</span>}
  return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-2 text-3xl font-semibold">Data export / import</h1><p className="mb-5 text-slate-500">Export jobs, preferences, or both. Hover or click an option to choose JSON, CSV, or XLSX. Import automatically detects what the file contains.</p><section className="mb-6 rounded border p-4"><h2 className="mb-3 text-xl font-semibold">Export</h2><div className="flex flex-wrap gap-3"><ExportChoice id="jobs" label="Jobs" icon="💼"/><ExportChoice id="preferences" label="Preferences" icon="⚙"/><ExportChoice id="full" label="Everything" icon="⬇"/></div></section><section className="rounded border p-4"><h2 className="mb-2 text-xl font-semibold">Import</h2><div role="button" tabIndex={0} onClick={()=>!loading&&fileInputRef.current?.click()} onKeyDown={e=>{if((e.key==='Enter'||e.key===' ')&&!loading){e.preventDefault();fileInputRef.current?.click()}}} onMouseEnter={()=>setDragging(true)} onMouseLeave={()=>setDragging(false)} onDragEnter={e=>{e.preventDefault();setDragging(true)}} onDragOver={e=>{e.preventDefault();setDragging(true)}} onDragLeave={e=>{e.preventDefault();setDragging(false)}} onDrop={e=>{e.preventDefault();setDragging(false);importFile(e.dataTransfer.files?.[0])}} className={(dragging?'scale-[1.01] border-blue-500 bg-blue-50 text-blue-900 shadow-md':'border-slate-300 bg-slate-50 text-slate-600 shadow-sm')+' mb-3 cursor-pointer rounded-xl border-2 border-dashed p-6 text-center transition duration-150 hover:scale-[1.01] hover:border-blue-500 hover:bg-blue-50 hover:text-blue-900 hover:shadow-md focus:outline-none focus:ring-2 focus:ring-blue-500'}><p className="font-medium">Drop a JSON, CSV, or XLSX export here</p><p className="mt-1 text-sm">or click this area to choose and import a file.</p>{loading?<p className="mt-3 text-sm font-semibold">Importing...</p>:file&&<p className="mt-3 text-sm"><b>Selected:</b> {file.name}</p>}</div><input ref={fileInputRef} className="hidden" type="file" accept="application/json,.json,text/csv,.csv,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,.xlsx" onChange={e=>importFile(e.target.files?.[0]||null)}/>{summary?.type==='import_conflicts'&&<div className="mt-4 rounded border border-yellow-200 bg-yellow-50 p-4 text-yellow-950"><h3 className="font-semibold">Import conflicts found</h3><p className="mb-3 text-sm">Some imported records match existing records. Choose one action for all conflicts.</p><div className="mb-3 flex flex-wrap gap-2"><button onClick={()=>importFile(file,'override')}>Override all</button><button onClick={()=>importFile(file,'duplicate')}>Duplicate all</button><button onClick={()=>importFile(file,'skip')}>Skip all</button><button className="bg-slate-500" onClick={()=>setSummary(null)}>Abort</button></div><div className="space-y-2">{summary.conflicts?.map((c:any)=><div key={c.index} className="rounded bg-white p-3 text-sm"><div><b>{c.kind==='update'?'Existing record would be updated':'Duplicate URL'}</b></div><div>Incoming: {c.incoming?.company||'Unknown company'} - {c.incoming?.title||'Untitled role'}</div>{c.changed_fields&&<div className="text-xs text-slate-600">Changed fields: {c.changed_fields.join(', ')}</div>}<div className="text-xs text-slate-600">Existing: {c.existing_jobs?.map((j:any)=>`#${j.id} ${j.company} - ${displayJobTitle(j.title)}`).join('; ')}</div></div>)}</div></div>}{summary&&summary.type!=='import_conflicts'&&<div className="mt-4"><SuccessMessage title="Import summary"><pre className="mt-2 overflow-auto rounded bg-white p-3 text-xs">{JSON.stringify(summary,null,2)}</pre>{summary.preferences&&<p className="mt-2 text-sm">Preferences were imported. Refresh the page if theme or table settings do not update immediately.</p>}</SuccessMessage></div>}<div className="mt-4"><ErrorBox error={err}/></div></section></div></main>
}
function Footer(){return <footer className="app-nav mt-auto border-t px-2 py-1 backdrop-blur-xl"><div className="flex w-full flex-wrap items-center justify-center gap-x-3 gap-y-0.5 text-[11px] text-slate-500 dark:text-slate-400"><span>© {new Date().getFullYear()} DACHApply</span><Link className="nav-link" to="/privacy">Privacy</Link><Link className="nav-link" to="/terms">Terms</Link></div></footer>}
function PrivacyPage(){const trust=['Your data stays in your private dashboard','No paid LLM API required','You control what gets pasted into ChatGPT','Export/delete anytime'];return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-3 text-3xl font-semibold">Privacy</h1><div className="space-y-3 text-sm text-slate-700"><p>DACHApply stores the account and job-search data needed to run your private dashboard.</p><div className="grid gap-2 sm:grid-cols-2">{trust.map(x=><div key={x} className="rounded-xl border border-emerald-200 bg-emerald-50 p-3 font-semibold text-emerald-950">✓ {x}</div>)}</div><ul className="list-disc space-y-1 pl-5"><li>Account email/username and password hash.</li><li>Candidate profile, scoring rules, and optional prompt templates.</li><li>Jobs, URLs, descriptions, evaluations, notes, follow-ups, statuses, and dates.</li><li>Friend-submission metadata when someone submits jobs for another user.</li></ul><p>AI is used through prompts you generate, review, and paste yourself. DACHApply does not require a paid LLM API key.</p><p>Password reset emails are sent only when requested. Invite codes are not included in user exports.</p><p>You can export your data from the Data page and delete your account from Account settings. Account deletion removes your profile and owned dashboard records.</p><p>DACHApply does not intentionally sell personal data. If you paste sensitive data into job descriptions, notes, or prompts, it is stored as part of your dashboard data.</p></div></div></main>}
function TermsPage(){return <main className="mx-auto max-w-3xl p-6"><div className="rounded bg-white p-6 shadow-sm"><h1 className="mb-3 text-3xl font-semibold">Terms</h1><div className="space-y-3 text-sm text-slate-700"><p>DACHApply is a job-search organization tool provided for private beta use.</p><ul className="list-disc space-y-1 pl-5"><li>Use the service only for lawful job-search and application management.</li><li>Do not submit spam, abusive content, or job links you are not allowed to share.</li><li>AI prompts and imported AI responses are user-controlled; verify all generated analysis before acting on it.</li><li>The service is provided as-is during beta and may change as features are improved.</li></ul><p>By using DACHApply, you agree to keep your login secure and to export your own data before deleting your account if you need a copy.</p></div></div></main>}
export default function App(){return <div className="flex min-h-screen flex-col"><RefreshSamePageLinks/><Nav/><GuidedOnboardingTour/><div className="flex-1"><Routes><Route path="/login" element={<Login/>}/><Route path="/privacy" element={<PrivacyPage/>}/><Route path="/terms" element={<TermsPage/>}/><Route path="/reset-password/:uid/:token" element={<ResetPassword/>}/><Route path="/onboarding" element={<RequireAuth><Onboarding/></RequireAuth>}/><Route path="/" element={<RequireAuth><OnboardingGate/></RequireAuth>}/><Route path="/add" element={<RequireAuth><JobForm/></RequireAuth>}/><Route path="/public-submit" element={<RequireAuth><JobForm publicMode/></RequireAuth>}/><Route path="/jobs/:id" element={<RequireAuth><Detail/></RequireAuth>}/><Route path="/prompts" element={<RequireAuth><Prompts/></RequireAuth>}/><Route path="/import" element={<RequireAuth><ImportEval/></RequireAuth>}/><Route path="/followups" element={<RequireAuth><Followups/></RequireAuth>}/><Route path="/export" element={<RequireAuth><Export/></RequireAuth>}/><Route path="/bookmarklet" element={<RequireAuth><Bookmarklet/></RequireAuth>}/><Route path="/settings/profile" element={<RequireAuth><ProfileSettings/></RequireAuth>}/><Route path="/settings/account" element={<RequireAuth><AccountSettings/></RequireAuth>}/></Routes></div><Footer/></div>}
